import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type AttendanceStatus = 'Duty' | 'SL' | 'PL' | 'CL' | 'Unpaid' | 'Half-Day' | 'Weekly Off' | 'Holiday' | 'Absent';

export interface AttendanceRecord {
  date: string; // ISO format
  checkIn?: string; // HH:mm
  checkOut?: string; // HH:mm
  status: AttendanceStatus;
  notes: string;
  totalHours?: number;
  otHours?: number;
}

export interface LeaveQuotas {
  SL: number;
  PL: number;
  CL: number;
}

export interface UserSettings {
  monthlySalary: number;
  otRate: number; // per hour
  dailyWorkHours: number; // usually 8.5
  quotas: LeaveQuotas;
}

export interface MonthlySummary {
  month: string;
  totalDays: number;
  presentDays: number;
  absentDays: number;
  halfDays: number;
  paidLeaves: number;
  unpaidLeaves: number;
  otHours: number;
  grossSalary: number;
  deductions: number;
  netSalary: number;
}

import { AttendanceRecord, UserSettings, AttendanceStatus } from './types';

export const formatTime = (time?: string) => time || '--:--';

export const calculateHours = (inTime: string, outTime: string): number => {
  const [inH, inM] = inTime.split(':').map(Number);
  const [outH, outM] = outTime.split(':').map(Number);

  let diff = (outH * 60 + outM) - (inH * 60 + inM);
  if (diff < 0) diff += 24 * 60; // Crosses midnight

  return parseFloat((diff / 60).toFixed(2));
};

export const getOT = (hours: number, dailyTarget: number = 8.5): number => {
  return Math.max(0, hours - dailyTarget);
};

export const calculateSalary = (records: AttendanceRecord[], settings: UserSettings) => {
  const dailyRate = settings.monthlySalary / 26;
  let totalOTHours = 0;
  let deductions = 0;
  let presentDays = 0;
  let halfDays = 0;
  let absentDays = 0;
  let paidLeavesUsed = 0;
  let unpaidLeavesUsed = 0;

  records.forEach(r => {
    if (r.status === 'Duty') {
      presentDays++;
      if (r.otHours) totalOTHours += r.otHours;
    } else if (r.status === 'Half-Day') {
      halfDays++;
      deductions += dailyRate * 0.5;
    } else if (r.status === 'Absent' || r.status === 'Unpaid') {
      absentDays++;
      deductions += dailyRate;
    } else if (['SL', 'PL', 'CL'].includes(r.status)) {
      paidLeavesUsed++;
    }
  });

  const otEarnings = totalOTHours * settings.otRate;
  const netSalary = settings.monthlySalary + otEarnings - deductions;

  return {
    dailyRate,
    totalOTHours,
    otEarnings,
    deductions,
    netSalary,
    presentDays,
    halfDays,
    absentDays,
    paidLeavesUsed,
  };
};

export const downloadCSV = (data: string, filename: string) => {
  const blob = new Blob([data], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement("a");
  const url = URL.createObjectURL(blob);
  link.setAttribute("href", url);
  link.setAttribute("download", filename);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar as CalendarIcon, 
  ClipboardList, 
  Settings as SettingsIcon,
  Sun,
  Moon,
  PlusCircle,
  Clock,
  LogOut,
  ChevronLeft,
  ChevronRight,
  Download
} from 'lucide-react';
import { AttendanceRecord, UserSettings, AttendanceStatus } from './types';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar';
import LeaveManager from './components/LeaveManager';
import SettingsView from './components/SettingsView';
import Reports from './components/Reports';
import { calculateSalary } from './utils';

const STORAGE_KEY = 'neon_attendance_v1';
const SETTINGS_KEY = 'neon_settings_v1';

const DEFAULT_SETTINGS: UserSettings = {
  monthlySalary: 30000,
  otRate: 200,
  dailyWorkHours: 8.5,
  quotas: { SL: 12, PL: 15, CL: 10 }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'leaves' | 'settings' | 'reports'>('dashboard');
  const [darkMode, setDarkMode] = useState(true);
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [settings, setSettings] = useState<UserSettings>(DEFAULT_SETTINGS);

  // Load data
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (saved) setRecords(JSON.parse(saved));
    if (savedSettings) setSettings(JSON.parse(savedSettings));
  }, []);

  // Save data
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [settings]);

  const stats = useMemo(() => {
    const currentMonth = new Date().toISOString().slice(0, 7);
    const monthlyRecords = records.filter(r => r.date.startsWith(currentMonth));
    return calculateSalary(monthlyRecords, settings);
  }, [records, settings]);

  const addRecord = (record: AttendanceRecord) => {
    setRecords(prev => {
      const filtered = prev.filter(r => r.date !== record.date);
      return [...filtered, record];
    });
  };

  const deleteRecord = (date: string) => {
    setRecords(prev => prev.filter(r => r.date !== date));
  };

  const NavItem = ({ id, icon: Icon, label }: { id: typeof activeTab, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center space-y-1 w-full py-2 transition-all ${
        activeTab === id ? 'text-sky-400 neon-text' : 'text-slate-400 hover:text-slate-200'
      }`}
    >
      <Icon size={20} />
      <span className="text-[10px] font-medium uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'} pb-24`}>
      {/* Header */}
      <header className="sticky top-0 z-50 glass border-b border-white/10 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 rounded-xl bg-sky-500 flex items-center justify-center shadow-lg shadow-sky-500/30">
            <Clock className="text-white" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold leading-none">NeonAttend</h1>
            <p className="text-[10px] uppercase text-sky-400 tracking-widest font-bold">Smart Salary Sync</p>
          </div>
        </div>
        <button 
          onClick={() => setDarkMode(!darkMode)}
          className="p-2 rounded-full glass border border-white/10 hover:bg-white/10 transition-colors"
        >
          {darkMode ? <Sun size={20} className="text-amber-400" /> : <Moon size={20} className="text-slate-600" />}
        </button>
      </header>

      {/* Main Content */}
      <main className="max-w-4xl mx-auto p-4 md:p-6">
        {activeTab === 'dashboard' && <Dashboard stats={stats} settings={settings} records={records} onAddRecord={addRecord} />}
        {activeTab === 'calendar' && <Calendar records={records} onAddRecord={addRecord} onDeleteRecord={deleteRecord} />}
        {activeTab === 'leaves' && <LeaveManager records={records} settings={settings} />}
        {activeTab === 'settings' && <SettingsView settings={settings} onSave={setSettings} />}
        {activeTab === 'reports' && <Reports records={records} settings={settings} />}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 z-50 glass-dark border-t border-white/10 px-2 py-1 safe-area-bottom">
        <div className="max-w-4xl mx-auto flex justify-around items-center">
          <NavItem id="dashboard" icon={LayoutDashboard} label="Home" />
          <NavItem id="calendar" icon={CalendarIcon} label="Log" />
          <NavItem id="leaves" icon={ClipboardList} label="Leaves" />
          <NavItem id="reports" icon={Download} label="Reports" />
          <NavItem id="settings" icon={SettingsIcon} label="Prefs" />
        </div>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AttendanceRecord, UserSettings, AttendanceStatus } from '../types';
import { Clock, TrendingUp, Calendar as Cal, AlertCircle, Plus, CheckCircle2 } from 'lucide-react';
import { calculateHours, getOT } from '../utils';

interface Props {
  stats: any;
  settings: UserSettings;
  records: AttendanceRecord[];
  onAddRecord: (r: AttendanceRecord) => void;
}

const Dashboard: React.FC<Props> = ({ stats, settings, records, onAddRecord }) => {
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isPunchedIn, setIsPunchedIn] = useState(false);
  const [activeSession, setActiveSession] = useState<Partial<AttendanceRecord> | null>(null);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    // Check if already punched in for today
    const today = new Date().toISOString().split('T')[0];
    const todayRecord = records.find(r => r.date === today);
    if (todayRecord && todayRecord.checkIn && !todayRecord.checkOut) {
      setIsPunchedIn(true);
      setActiveSession(todayRecord);
    } else {
      setIsPunchedIn(false);
      setActiveSession(null);
    }
    return () => clearInterval(timer);
  }, [records]);

  const handleQuickPunch = () => {
    const now = new Date();
    const dateStr = now.toISOString().split('T')[0];
    const timeStr = now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });

    if (!isPunchedIn) {
      // Punch In
      onAddRecord({
        date: dateStr,
        checkIn: timeStr,
        status: 'Duty',
        notes: '',
      });
      setIsPunchedIn(true);
    } else {
      // Punch Out
      const existing = records.find(r => r.date === dateStr);
      if (existing && existing.checkIn) {
        const totalHours = calculateHours(existing.checkIn, timeStr);
        const otHours = getOT(totalHours, settings.dailyWorkHours);
        onAddRecord({
          ...existing,
          checkOut: timeStr,
          totalHours,
          otHours,
        });
      }
      setIsPunchedIn(false);
    }
  };

  const StatCard = ({ label, value, icon: Icon, color, suffix = "" }: any) => (
    <div className="glass p-4 rounded-2xl flex flex-col justify-between border border-white/5 shadow-xl">
      <div className="flex justify-between items-start mb-2">
        <span className="text-slate-400 text-xs font-semibold uppercase tracking-wider">{label}</span>
        <div className={`p-2 rounded-lg bg-${color}-500/10`}>
          <Icon size={16} className={`text-${color}-400`} />
        </div>
      </div>
      <div className="flex items-baseline space-x-1">
        <span className="text-2xl font-bold font-heading">{value}</span>
        <span className="text-[10px] text-slate-500 font-medium">{suffix}</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      {/* Hero Section */}
      <div className="glass rounded-3xl p-6 relative overflow-hidden border border-sky-500/20 bg-gradient-to-br from-sky-500/10 to-transparent">
        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-1">
            <h2 className="text-3xl font-bold tracking-tight">Welcome back!</h2>
            <p className="text-slate-400">It's {currentTime.toLocaleDateString('en-US', { weekday: 'long', day: 'numeric', month: 'long' })}</p>
            <div className="text-5xl font-bold font-heading neon-text text-sky-400 mt-2">
              {currentTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true })}
            </div>
          </div>

          <div className="flex flex-col items-center">
            <button
              onClick={handleQuickPunch}
              className={`group relative w-40 h-40 rounded-full border-4 transition-all duration-500 flex flex-center items-center justify-center flex-col gap-2 ${
                isPunchedIn 
                  ? 'border-rose-500 shadow-[0_0_30px_rgba(244,63,94,0.4)] bg-rose-500/10' 
                  : 'border-emerald-500 shadow-[0_0_30px_rgba(16,185,129,0.4)] bg-emerald-500/10'
              }`}
            >
              <Plus size={48} className={`transition-transform duration-500 ${isPunchedIn ? 'rotate-45 text-rose-500' : 'text-emerald-500'}`} />
              <span className={`font-bold uppercase tracking-widest text-xs ${isPunchedIn ? 'text-rose-500' : 'text-emerald-500'}`}>
                {isPunchedIn ? 'PUNCH OUT' : 'PUNCH IN'}
              </span>
            </button>
            {isPunchedIn && activeSession && (
              <p className="mt-4 text-sm text-sky-400 animate-pulse font-medium">
                Punched in at: {activeSession.checkIn}
              </p>
            )}
          </div>
        </div>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard label="Present" value={stats.presentDays} icon={CheckCircle2} color="sky" suffix="days" />
        <StatCard label="Overtime" value={stats.totalOTHours} icon={Clock} color="amber" suffix="hrs" />
        <StatCard label="Deductions" value={Math.round(stats.deductions)} icon={AlertCircle} color="rose" suffix="INR" />
        <StatCard label="Leaves" value={stats.paidLeavesUsed} icon={Cal} color="purple" suffix="days" />
      </div>

      {/* Salary Overview */}
      <div className="glass rounded-2xl p-6 border border-white/5 overflow-hidden group">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="text-lg font-bold">Monthly Estimated Payout</h3>
            <p className="text-xs text-slate-500 uppercase">Based on current month records</p>
          </div>
          <div className="p-2 rounded-full bg-sky-500/20">
            <TrendingUp size={24} className="text-sky-400" />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-1">
            <span className="text-slate-500 text-xs">Gross Salary</span>
            <p className="text-2xl font-bold">₹{settings.monthlySalary.toLocaleString()}</p>
          </div>
          <div className="space-y-1">
            <span className="text-slate-500 text-xs">OT Bonus (+{stats.totalOTHours}h)</span>
            <p className="text-2xl font-bold text-emerald-400">₹{Math.round(stats.otEarnings).toLocaleString()}</p>
          </div>
          <div className="space-y-1 p-4 bg-sky-500/10 rounded-xl border border-sky-500/20">
            <span className="text-sky-400 text-xs font-bold uppercase">Net Payable</span>
            <p className="text-3xl font-bold neon-text">₹{Math.round(stats.netSalary).toLocaleString()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { AttendanceRecord, AttendanceStatus } from '../types';
import { ChevronLeft, ChevronRight, Edit3, Trash2, Clock, X } from 'lucide-react';
import { calculateHours, getOT } from '../utils';

interface Props {
  records: AttendanceRecord[];
  onAddRecord: (r: AttendanceRecord) => void;
  onDeleteRecord: (date: string) => void;
}

const STATUS_CONFIG: Record<AttendanceStatus, { color: string, bg: string }> = {
  'Duty': { color: 'text-emerald-400', bg: 'bg-emerald-500/20' },
  'SL': { color: 'text-rose-400', bg: 'bg-rose-500/20' },
  'PL': { color: 'text-amber-400', bg: 'bg-amber-500/20' },
  'CL': { color: 'text-purple-400', bg: 'bg-purple-500/20' },
  'Unpaid': { color: 'text-slate-400', bg: 'bg-slate-500/20' },
  'Half-Day': { color: 'text-orange-400', bg: 'bg-orange-500/20' },
  'Weekly Off': { color: 'text-sky-400', bg: 'bg-sky-500/10' },
  'Holiday': { color: 'text-pink-400', bg: 'bg-pink-500/20' },
  'Absent': { color: 'text-rose-600', bg: 'bg-rose-600/10' },
};

const Calendar: React.FC<Props> = ({ records, onAddRecord, onDeleteRecord }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);

  // Form State
  const [formData, setFormData] = useState<Partial<AttendanceRecord>>({
    status: 'Duty',
    checkIn: '09:00',
    checkOut: '17:30',
    notes: '',
  });

  const monthStart = new Date(viewDate.getFullYear(), viewDate.getMonth(), 1);
  const daysInMonth = new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  const startDay = monthStart.getDay();

  const handlePrevMonth = () => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1));
  const handleNextMonth = () => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1));

  const days = Array.from({ length: daysInMonth }, (_, i) => {
    const d = new Date(viewDate.getFullYear(), viewDate.getMonth(), i + 1);
    const dateStr = d.toISOString().split('T')[0];
    const record = records.find(r => r.date === dateStr);
    return { date: dateStr, day: i + 1, record };
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDate) return;

    let finalRecord: AttendanceRecord = {
      date: selectedDate,
      status: formData.status as AttendanceStatus,
      notes: formData.notes || '',
    };

    if (formData.status === 'Duty' || formData.status === 'Half-Day') {
      if (formData.checkIn && formData.checkOut) {
        const total = calculateHours(formData.checkIn, formData.checkOut);
        finalRecord = {
          ...finalRecord,
          checkIn: formData.checkIn,
          checkOut: formData.checkOut,
          totalHours: total,
          otHours: getOT(total),
        };
      }
    }

    onAddRecord(finalRecord);
    setShowForm(false);
  };

  const openForm = (date: string, existing?: AttendanceRecord) => {
    setSelectedDate(date);
    if (existing) {
      setFormData({
        status: existing.status,
        checkIn: existing.checkIn || '09:00',
        checkOut: existing.checkOut || '17:30',
        notes: existing.notes || '',
      });
    } else {
      setFormData({
        status: 'Duty',
        checkIn: '09:00',
        checkOut: '17:30',
        notes: '',
      });
    }
    setShowForm(true);
  };

  return (
    <div className="space-y-6">
      {/* Calendar Header */}
      <div className="flex justify-between items-center glass p-4 rounded-2xl border border-white/5">
        <h2 className="text-xl font-bold font-heading">
          {viewDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
        </h2>
        <div className="flex space-x-2">
          <button onClick={handlePrevMonth} className="p-2 hover:bg-white/10 rounded-full transition-colors"><ChevronLeft size={20} /></button>
          <button onClick={handleNextMonth} className="p-2 hover:bg-white/10 rounded-full transition-colors"><ChevronRight size={20} /></button>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-7 gap-2">
        {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => (
          <div key={d} className="text-center text-[10px] font-bold text-slate-500 uppercase py-2">{d}</div>
        ))}
        {Array.from({ length: startDay }).map((_, i) => <div key={`empty-${i}`} />)}
        {days.map(({ date, day, record }) => (
          <button
            key={date}
            onClick={() => openForm(date, record)}
            className={`aspect-square glass rounded-xl flex flex-col items-center justify-center relative transition-all active:scale-95 border border-white/5 group ${
              record ? 'shadow-lg' : 'hover:border-sky-500/30'
            }`}
          >
            <span className={`text-sm font-medium ${record ? 'text-white' : 'text-slate-400'}`}>{day}</span>
            {record && (
              <div className={`mt-1 h-1.5 w-1.5 rounded-full ${STATUS_CONFIG[record.status].bg.replace('bg-', 'bg-opacity-100 bg-')}`} />
            )}
            {record && record.status === 'Duty' && (
              <span className="absolute bottom-1 text-[8px] text-slate-500 font-mono">{record.totalHours}h</span>
            )}
          </button>
        ))}
      </div>

      {/* Form Modal */}
      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowForm(false)} />
          <div className="relative w-full max-w-md glass p-6 rounded-3xl border border-sky-500/30 shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold">Log Attendance</h3>
              <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-white"><X size={24} /></button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Attendance Status</label>
                <div className="grid grid-cols-3 gap-2">
                  {(Object.keys(STATUS_CONFIG) as AttendanceStatus[]).map(s => (
                    <button
                      key={s}
                      type="button"
                      onClick={() => setFormData({ ...formData, status: s })}
                      className={`py-2 px-1 text-[10px] rounded-lg border font-bold transition-all ${
                        formData.status === s 
                          ? 'border-sky-500 bg-sky-500/20 text-sky-400' 
                          : 'border-white/5 bg-white/5 text-slate-400'
                      }`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              {(formData.status === 'Duty' || formData.status === 'Half-Day') && (
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Check In</label>
                    <input
                      type="time"
                      value={formData.checkIn}
                      onChange={e => setFormData({ ...formData, checkIn: e.target.value })}
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-sky-500"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Check Out</label>
                    <input
                      type="time"
                      value={formData.checkOut}
                      onChange={e => setFormData({ ...formData, checkOut: e.target.value })}
                      className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2 text-white focus:outline-none focus:border-sky-500"
                    />
                  </div>
                </div>
              )}

              <div>
                <label className="block text-xs font-bold text-slate-500 uppercase mb-2">Notes</label>
                <textarea
                  value={formData.notes}
