const EMPLOYEES_KEY = 'neon_employees_v2';
const RECORDS_KEY = 'neon_records_v2';
const LEAVES_KEY = 'neon_leaves_v2';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'leaves' | 'settings' | 'reports' | 'staff' | 'approvals'>('dashboard');
  const [darkMode, setDarkMode] = useState(true);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [selectedEmployeeId, setSelectedEmployeeId] = useState<string | null>(null);

  // Load data
  useEffect(() => {
    const savedEmployees = localStorage.getItem(EMPLOYEES_KEY);
    const savedRecords = localStorage.getItem(RECORDS_KEY);
    const savedLeaves = localStorage.getItem(LEAVES_KEY);

    if (savedEmployees) setEmployees(JSON.parse(savedEmployees));
    if (savedRecords) setRecords(JSON.parse(savedRecords));
    if (savedLeaves) setLeaveRequests(JSON.parse(savedLeaves));
  }, []);

  // Save data
  useEffect(() => { localStorage.setItem(EMPLOYEES_KEY, JSON.stringify(employees)); }, [employees]);
  useEffect(() => { localStorage.setItem(RECORDS_KEY, JSON.stringify(records)); }, [records]);
  useEffect(() => { localStorage.setItem(LEAVES_KEY, JSON.stringify(leaveRequests)); }, [leaveRequests]);

  const selectedEmployee = useMemo(() => 
    employees.find(e => e.id === selectedEmployeeId) || employees[0], 
  [employees, selectedEmployeeId]);

  const stats = useMemo(() => {
    if (!selectedEmployee) return null;
    const currentMonth = new Date().toISOString().slice(0, 7);
    const monthlyRecords = records.filter(r => r.employeeId === selectedEmployee.id && r.date.startsWith(currentMonth));
    return calculateSalary(monthlyRecords, selectedEmployee);
  }, [records, selectedEmployee]);

  const addRecord = (record: AttendanceRecord) => {
    setRecords(prev => {
      const filtered = prev.filter(r => !(r.date === record.date && r.employeeId === record.employeeId));
      return [...filtered, record];
    });
  };

  const deleteRecord = (date: string, employeeId: string) => {
    setRecords(prev => prev.filter(r => !(r.date === date && r.employeeId === employeeId)));
  };

  const handleApproveLeave = (req: LeaveRequest) => {
    // 1. Update Request
    setLeaveRequests(prev => prev.map(l => l.id === req.id ? { ...l, status: 'Approved' } : l));

    // 2. Generate Attendance Records for each day in range
    const start = new Date(req.startDate);
    const end = new Date(req.endDate);
    const newRecords: AttendanceRecord[] = [];

    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      newRecords.push({
        employeeId: req.employeeId,
        date: d.toISOString().split('T')[0],
        status: req.type,
        notes: `Approved Leave: ${req.reason}`
      });
    }

    setRecords(prev => {
      const filtered = prev.filter(r => 
        !(r.employeeId === req.employeeId && r.date >= req.startDate && r.date <= req.endDate)
      );
      return [...filtered, ...newRecords];
    });
  };

  const NavItem = ({ id, icon: Icon, label }: { id: typeof activeTab, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center space-y-1 w-full py-2 transition-all ${
        activeTab === id ? 'text-sky-400 neon-text' : 'text-slate-400 hover:text-slate-200'
      }`}
    >
      <Icon size={20} />
      <span className="text-[8px] font-medium uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
