        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 rounded-xl bg-sky-500 flex items-center justify-center shadow-lg shadow-sky-500/30">
            <Clock className="text-white" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold leading-none">NeonStaff</h1>
            <p className="text-[10px] uppercase text-sky-400 tracking-widest font-bold">Manager Mode</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {employees.length > 0 && (
            <select 
              value={selectedEmployeeId || ''} 
              onChange={(e) => setSelectedEmployeeId(e.target.value)}
              className="bg-slate-900 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-sky-400 font-bold focus:outline-none"
            >
              {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
            </select>
          )}
          <button 
            onClick={() => setDarkMode(!darkMode)}
            className="p-2 rounded-full glass border border-white/10 hover:bg-white/10 transition-colors"
          >
            {darkMode ? <Sun size={20} className="text-amber-400" /> : <Moon size={20} className="text-slate-600" />}
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 md:p-6">
        {employees.length === 0 && activeTab !== 'staff' ? (
          <div className="text-center py-20 space-y-4">
            <Users size={64} className="mx-auto text-slate-700" />
            <h2 className="text-2xl font-bold">No Employees Yet</h2>
            <p className="text-slate-500">Add your first employee to get started.</p>
            <button onClick={() => setActiveTab('staff')} className="px-6 py-3 bg-sky-500 rounded-xl font-bold">Add Staff</button>
          </div>
        ) : (
          <>
            {activeTab === 'dashboard' && selectedEmployee && <Dashboard stats={stats} employee={selectedEmployee} records={records} onAddRecord={addRecord} />}
            {activeTab === 'calendar' && selectedEmployee && <Calendar employee={selectedEmployee} records={records.filter(r => r.employeeId === selectedEmployee.id)} onAddRecord={addRecord} onDeleteRecord={(d) => deleteRecord(d, selectedEmployee.id)} />}
            {activeTab === 'leaves' && selectedEmployee && <LeaveManager employee={selectedEmployee} records={records.filter(r => r.employeeId === selectedEmployee.id)} leaveRequests={leaveRequests.filter(l => l.employeeId === selectedEmployee.id)} onAddRequest={(req) => setLeaveRequests(prev => [...prev, req])} />}
            {activeTab === 'reports' && selectedEmployee && <Reports employee={selectedEmployee} records={records.filter(r => r.employeeId === selectedEmployee.id)} />}
            {activeTab === 'staff' && <StaffManager employees={employees} onAdd={(e) => setEmployees([...employees, e])} onUpdate={(e) => setEmployees(employees.map(emp => emp.id === e.id ? e : emp))} onDelete={(id) => setEmployees(employees.filter(e => e.id !== id))} />}
            {activeTab === 'approvals' && <LeaveApproval requests={leaveRequests} employees={employees} onApprove={handleApproveLeave} onReject={(id) => setLeaveRequests(prev => prev.map(l => l.id === id ? { ...l, status: 'Rejected' } : l))} />}
            {activeTab === 'settings' && <SettingsView onUpdateDefaults={() => {}} />}
          </>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 z-50 glass-dark border-t border-white/10 px-2 py-1 safe-area-bottom overflow-x-auto">
        <div className="max-w-4xl mx-auto flex justify-around items-center min-w-[400px]">
          <NavItem id="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem id="staff" icon={Users} label="Staff" />
          <NavItem id="calendar" icon={CalendarIcon} label="Log" />
          <NavItem id="approvals" icon={MessageSquare} label="Approvals" />
          <NavItem id="leaves" icon={ClipboardList} label="My Leaves" />
          <NavItem id="reports" icon={Download} label="Reports" />
        </div>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { AttendanceRecord, Employee } from '../types';
import { Clock, TrendingUp, Calendar as Cal, AlertCircle, Plus, CheckCircle2, User } from 'lucide-react';
import { calculateHours, getOT } from '../utils';

interface Props {
  stats: any;
  employee: Employee;
  records: AttendanceRecord[];
  onAddRecord: (r: AttendanceRecord) => void;
}

const Dashboard: React.FC<Props> = ({ stats, employee, records, onAddRecord }) => {
  const [currentTime, setCurrentTime] = useState(new Date());
  const [isPunchedIn, setIsPunchedIn] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
    const today = new Date().toISOString().split('T')[0];
    const todayRecord = records.find(r => r.date === today && r.employeeId === employee.id);
    setIsPunchedIn(!!(todayRecord && todayRecord.checkIn && !todayRecord.checkOut));
    return () => clearInterval(timer);
  }, [records, employee.id]);

  const handleQuickPunch = () => {
    const now = new Date();
    const dateStr = now.toISOString().split('T')[0];
    const timeStr = now.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });

    if (!isPunchedIn) {
      onAddRecord({ employeeId: employee.id, date: dateStr, checkIn: timeStr, status: 'Duty', notes: '' });
    } else {
      const existing = records.find(r => r.date === dateStr && r.employeeId === employee.id);
      if (existing && existing.checkIn) {
        const totalHours = calculateHours(existing.checkIn, timeStr);
        const otHours = getOT(totalHours, employee.dailyWorkHours);
        onAddRecord({ ...existing, checkOut: timeStr, totalHours, otHours });
      }
    }
  };

  const StatCard = ({ label, value, icon: Icon, color, suffix = "" }: any) => (
    <div className="glass p-4 rounded-2xl flex flex-col justify-between border border-white/5 shadow-xl">
      <div className="flex justify-between items-start mb-2">
        <span className="text-slate-400 text-[10px] font-semibold uppercase tracking-wider">{label}</span>
        <div className={`p-2 rounded-lg bg-${color}-500/10`}>
          <Icon size={14} className={`text-${color}-400`} />
        </div>
      </div>
      <div className="flex items-baseline space-x-1">
        <span className="text-xl font-bold font-heading">{value}</span>
        <span className="text-[8px] text-slate-500 font-medium">{suffix}</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="glass rounded-3xl p-6 relative overflow-hidden border border-sky-500/20 bg-gradient-to-br from-sky-500/10 to-transparent">
        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-sky-400">
              <User size={18} />
              <span className="font-bold uppercase tracking-widest text-xs">{employee.role}</span>
            </div>
            <h2 className="text-3xl font-bold tracking-tight">{employee.name}</h2>
            <p className="text-slate-400">Punched in: {isPunchedIn ? 'ACTIVE' : 'OFF DUTY'}</p>
            <div className="text-4xl font-bold font-heading neon-text text-sky-400">
              {currentTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true })}
            </div>
          </div>

          <button
            onClick={handleQuickPunch}
            className={`w-32 h-32 rounded-full border-4 transition-all duration-500 flex items-center justify-center flex-col gap-1 ${
              isPunchedIn ? 'border-rose-500 shadow-[0_0_20px_rgba(244,63,94,0.4)] bg-rose-500/10' : 'border-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.4)] bg-emerald-500/10'
            }`}
          >
            <Plus size={32} className={isPunchedIn ? 'rotate-45 text-rose-500' : 'text-emerald-500'} />
            <span className={`font-bold uppercase tracking-widest text-[8px] ${isPunchedIn ? 'text-rose-500' : 'text-emerald-500'}`}>
              {isPunchedIn ? 'OUT' : 'IN'}
            </span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard label="Present" value={stats.presentDays} icon={CheckCircle2} color="sky" suffix="days" />
        <StatCard label="OT Hours" value={stats.totalOTHours} icon={Clock} color="amber" suffix="hrs" />
        <StatCard label="Deductions" value={Math.round(stats.deductions)} icon={AlertCircle} color="rose" suffix="INR" />
        <StatCard label="Paid Leaves" value={stats.paidLeavesUsed} icon={Cal} color="purple" suffix="days" />
      </div>

      <div className="glass rounded-2xl p-6 border border-white/5">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h3 className="text-lg font-bold">Estimated Net Payout</h3>
            <p className="text-xs text-slate-500 uppercase">Current cycle estimate</p>
          </div>
          <TrendingUp size={20} className="text-sky-400" />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div>
            <span className="text-slate-500 text-[10px] uppercase font-bold">Base Pay</span>
            <p className="text-xl font-bold">₹{employee.monthlySalary.toLocaleString()}</p>
          </div>
          <div>
            <span className="text-slate-500 text-[10px] uppercase font-bold">OT ({employee.otRate}/hr)</span>
            <p className="text-xl font-bold text-emerald-400">+₹{Math.round(stats.otEarnings).toLocaleString()}</p>
          </div>
          <div className="p-4 bg-sky-500/10 rounded-xl border border-sky-500/20">
            <span className="text-sky-400 text-[10px] font-bold uppercase">Final Payout</span>
            <p className="text-2xl font-bold neon-text">₹{Math.round(stats.netSalary).toLocaleString()}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Employee } from '../types';
import { Plus, User, Edit2, Trash2, X, Shield, Wallet } from 'lucide-react';

interface Props {
  employees: Employee[];
  onAdd: (e: Employee) => void;
  onUpdate: (e: Employee) => void;
  onDelete: (id: string) => void;
}

const StaffManager: React.FC<Props> = ({ employees, onAdd, onUpdate, onDelete }) => {
  const [showModal, setShowModal] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    role: 'Staff',
    salary: 30000,
    otRate: 200,
    dailyHours: 8.5,
    sl: 12, pl: 15, cl: 10
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newEmp: Employee = {
      id: editingEmployee?.id || Date.now().toString(),
      name: formData.name,
      role: formData.role,
      monthlySalary: formData.salary,
      otRate: formData.otRate,
      dailyWorkHours: formData.dailyHours,
      joinedDate: editingEmployee?.joinedDate || new Date().toISOString(),
      quotas: { SL: formData.sl, PL: formData.pl, CL: formData.cl }
    };

    if (editingEmployee) onUpdate(newEmp);
    else onAdd(newEmp);

    setShowModal(false);
    setEditingEmployee(null);
  };

  const handleEdit = (emp: Employee) => {
    setEditingEmployee(emp);
    setFormData({
      name: emp.name,
      role: emp.role,
      salary: emp.monthlySalary,
      otRate: emp.otRate,
      dailyHours: emp.dailyWorkHours,
      sl: emp.quotas.SL, pl: emp.quotas.PL, cl: emp.quotas.CL
    });
    setShowModal(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">Staff Directory</h2>
        <button 
          onClick={() => { setShowModal(true); setEditingEmployee(null); setFormData({name: '', role: 'Staff', salary: 30000, otRate: 200, dailyHours: 8.5, sl: 12, pl: 15, cl: 10}); }}
          className="flex items-center gap-2 bg-sky-500 px-4 py-2 rounded-xl font-bold text-sm"
        >
          <Plus size={18} /> Add Employee
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {employees.map(emp => (
          <div key={emp.id} className="glass p-5 rounded-2xl border border-white/5 flex items-center justify-between group">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-slate-800 flex items-center justify-center text-sky-400">
                <User size={24} />
              </div>
              <div>
                <h4 className="font-bold">{emp.name}</h4>
                <p className="text-xs text-slate-500 uppercase tracking-widest">{emp.role}</p>
              </div>
            </div>
            <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => handleEdit(emp)} className="p-2 bg-sky-500/10 text-sky-400 rounded-lg"><Edit2 size={16} /></button>
              <button onClick={() => onDelete(emp.id)} className="p-2 bg-rose-500/10 text-rose-500 rounded-lg"><Trash2 size={16} /></button>
            </div>
          </div>
        ))}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-sm" onClick={() => setShowModal(false)} />
          <div className="relative glass w-full max-w-lg p-8 rounded-3xl border border-sky-500/30">
            <h3 className="text-xl font-bold mb-6">{editingEmployee ? 'Edit' : 'New'} Employee</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-500 uppercase">Name</label>
                  <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" required />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-500 uppercase">Role</label>
                  <input value={formData.role} onChange={e => setFormData({...formData, role: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
                </div>
              </div>
              <div className="grid grid-cols-3 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-500 uppercase">Salary (INR)</label>
                  <input type="number" value={formData.salary} onChange={e => setFormData({...formData, salary: Number(e.target.value)})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-500 uppercase">OT Rate</label>
                  <input type="number" value={formData.otRate} onChange={e => setFormData({...formData, otRate: Number(e.target.value)})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-500 uppercase">Duty Hrs</label>
                  <input type="number" value={formData.dailyHours} onChange={e => setFormData({...formData, dailyHours: Number(e.target.value)})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
                </div>
              </div>
              <div className="pt-2">
                <label className="text-[10px] font-bold text-slate-500 uppercase block mb-2">Leave Quotas (Yearly)</label>
