import React from 'react';
import { LeaveRequest, Employee } from '../types';
import { Check, X, Clock, Calendar } from 'lucide-react';

interface Props {
  requests: LeaveRequest[];
  employees: Employee[];
  onApprove: (req: LeaveRequest) => void;
  onReject: (id: string) => void;
}

const LeaveApproval: React.FC<Props> = ({ requests, employees, onApprove, onReject }) => {
  const pending = requests.filter(r => r.status === 'Pending').sort((a,b) => b.createdAt.localeCompare(a.createdAt));

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">Leave Requests</h2>
        <span className="bg-amber-500/10 text-amber-500 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border border-amber-500/20">
          {pending.length} Pending
        </span>
      </div>

      <div className="space-y-4">
        {pending.length === 0 ? (
          <div className="glass p-12 text-center rounded-3xl border border-white/5 italic text-slate-500">
            No pending leave requests at the moment.
          </div>
        ) : (
          pending.map(req => {
            const emp = employees.find(e => e.id === req.employeeId);
            return (
              <div key={req.id} className="glass p-6 rounded-3xl border border-white/5 flex flex-col md:flex-row md:items-center justify-between gap-4 animate-in slide-in-from-right duration-300">
                <div className="flex gap-4">
                  <div className="w-12 h-12 bg-sky-500/10 rounded-2xl flex items-center justify-center text-sky-400">
                    <Calendar size={24} />
                  </div>
                  <div>
                    <h4 className="font-bold text-lg">{emp?.name || 'Unknown Staff'}</h4>
                    <p className="text-xs text-slate-400 mb-2">Requested {req.type} for {req.startDate} to {req.endDate}</p>
                    <p className="text-sm bg-white/5 p-3 rounded-xl italic">"{req.reason}"</p>
                  </div>
                </div>
                <div className="flex gap-3">
                  <button 
                    onClick={() => onApprove(req)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-500 px-6 py-2.5 rounded-xl font-bold text-sm shadow-lg shadow-emerald-500/20"
                  >
                    <Check size={18} /> Approve
                  </button>
                  <button 
                    onClick={() => onReject(req.id)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-rose-500/10 text-rose-500 border border-rose-500/20 px-6 py-2.5 rounded-xl font-bold text-sm"
                  >
                    <X size={18} /> Reject
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* History section */}
      <div className="mt-12">
        <h3 className="text-lg font-bold mb-4">Request History</h3>
        <div className="glass rounded-2xl overflow-hidden divide-y divide-white/5">
          {requests.filter(r => r.status !== 'Pending').slice(0, 10).map(req => {
            const emp = employees.find(e => e.id === req.employeeId);
            return (
              <div key={req.id} className="p-4 flex items-center justify-between text-sm">
                <div>
                  <span className="font-bold">{emp?.name}</span>
                  <span className="text-slate-500 mx-2">•</span>
                  <span className="text-slate-400">{req.startDate}</span>
                </div>
                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                  req.status === 'Approved' ? 'text-emerald-400 bg-emerald-500/10' : 'text-rose-400 bg-rose-500/10'
                }`}>
                  {req.status}
                </span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default LeaveApproval;

import React, { useState } from 'react';
import { AttendanceRecord, Employee, LeaveRequest } from '../types';
import { ClipboardList, PieChart, Plus, X } from 'lucide-react';

interface Props {
  employee: Employee;
  records: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onAddRequest: (r: LeaveRequest) => void;
}

const LeaveManager: React.FC<Props> = ({ employee, records, leaveRequests, onAddRequest }) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({ type: 'PL' as any, start: '', end: '', reason: '' });

  const currentYear = new Date().getFullYear().toString();
  const yearlyRecords = records.filter(r => r.date.startsWith(currentYear));

  const getUsage = (type: string) => yearlyRecords.filter(r => r.status === type).length;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddRequest({
      id: Date.now().toString(),
      employeeId: employee.id,
      type: formData.type,
      startDate: formData.start,
      endDate: formData.end,
      reason: formData.reason,
      status: 'Pending',
      createdAt: new Date().toISOString()
    });
    setShowForm(false);
  };

  const LeaveCard = ({ label, used, total, color }: any) => {
    const remaining = total - used;
    const progress = (used / total) * 100;
    return (
      <div className="glass p-5 rounded-2xl border border-white/5 space-y-4">
        <div className="flex justify-between items-center">
          <h4 className="font-bold text-lg">{label}</h4>
          <span className={`text-[10px] px-2 py-1 rounded-md bg-${color}-500/10 text-${color}-400 font-bold uppercase`}>Yearly</span>
        </div>
        <div className="flex items-baseline space-x-2">
          <span className="text-3xl font-bold font-heading">{remaining}</span>
          <span className="text-slate-500 text-xs">days left</span>
        </div>
        <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
          <div className={`h-full bg-${color}-500`} style={{ width: `${Math.min(100, progress)}%` }} />
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">Leave Center</h2>
          <p className="text-slate-500 text-sm">Apply and track leave history</p>
        </div>
        <button onClick={() => setShowForm(true)} className="bg-sky-500 px-4 py-2 rounded-xl font-bold text-sm flex items-center gap-2">
          <Plus size={18} /> Apply Leave
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <LeaveCard label="Sick (SL)" used={getUsage('SL')} total={employee.quotas.SL} color="rose" />
        <LeaveCard label="Paid (PL)" used={getUsage('PL')} total={employee.quotas.PL} color="emerald" />
        <LeaveCard label="Casual (CL)" used={getUsage('CL')} total={employee.quotas.CL} color="purple" />
      </div>

      <div className="glass rounded-3xl overflow-hidden border border-white/5">
        <div className="p-4 border-b border-white/5 bg-white/5 font-bold flex items-center gap-2"><PieChart size={18}/> Request Status</div>
        <div className="divide-y divide-white/5">
          {leaveRequests.length > 0 ? leaveRequests.sort((a,b) => b.createdAt.localeCompare(a.createdAt)).map(r => (
            <div key={r.id} className="p-4 flex justify-between items-center">
              <div>
                <p className="font-bold text-sm">{r.type} Request</p>
                <p className="text-xs text-slate-500">{r.startDate} to {r.endDate}</p>
              </div>
              <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${
                r.status === 'Pending' ? 'bg-amber-500/10 text-amber-500' : 
                r.status === 'Approved' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-rose-500/10 text-rose-500'
              }`}>
                {r.status}
              </span>
            </div>
          )) : <p className="p-8 text-center text-slate-500 text-sm">No recent requests</p>}
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-sm" onClick={() => setShowForm(false)} />
          <form onSubmit={handleSubmit} className="relative glass w-full max-w-md p-8 rounded-3xl border border-sky-500/30 space-y-4">
            <h3 className="text-xl font-bold">New Leave Application</h3>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-500 uppercase">Type</label>
              <select value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2">
                <option value="PL">Paid Leave (PL)</option>
                <option value="SL">Sick Leave (SL)</option>
                <option value="CL">Casual Leave (CL)</option>
              </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">Start</label>
                <input type="date" required value={formData.start} onChange={e => setFormData({...formData, start: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 uppercase">End</label>
                <input type="date" required value={formData.end} onChange={e => setFormData({...formData, end: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-500 uppercase">Reason</label>
              <textarea required value={formData.reason} onChange={e => setFormData({...formData, reason: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2 h-24" />
            </div>
            <button type="submit" className="w-full py-3 bg-sky-500 rounded-xl font-bold shadow-lg shadow-sky-500/20">Submit Application</button>
          </form>
        </div>
      )}
    </div>
  );
};

export default LeaveManager;

import React, { useState } from 'react';
import { AttendanceRecord, AttendanceStatus, Employee } from '../types';
import { ChevronLeft, ChevronRight, Trash2, X } from 'lucide-react';
import { calculateHours, getOT } from '../utils';

interface Props {
  employee: Employee;
  records: AttendanceRecord[];
  onAddRecord: (r: AttendanceRecord) => void;
  onDeleteRecord: (date: string) => void;
}

const STATUS_CONFIG: Record<AttendanceStatus, { color: string, bg: string }> = {
  'Duty': { color: 'text-emerald-400', bg: 'bg-emerald-500/20' },
  'SL': { color: 'text-rose-400', bg: 'bg-rose-500/20' },
  'PL': { color: 'text-amber-400', bg: 'bg-amber-500/20' },
  'CL': { color: 'text-purple-400', bg: 'bg-purple-500/20' },
  'Unpaid': { color: 'text-slate-400', bg: 'bg-slate-500/20' },
  'Half-Day': { color: 'text-orange-400', bg: 'bg-orange-500/20' },
  'Weekly Off': { color: 'text-sky-400', bg: 'bg-sky-500/10' },
  'Holiday': { color: 'text-pink-400', bg: 'bg-pink-500/20' },
  'Absent': { color: 'text-rose-600', bg: 'bg-rose-600/10' },
};

const Calendar: React.FC<Props> = ({ employee, records, onAddRecord, onDeleteRecord }) => {
  const [viewDate, setViewDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState<Partial<AttendanceRecord>>({ status: 'Duty', checkIn: '09:00', checkOut: '17:30', notes: '' });

  const monthStart = new Date(viewDate.getFullYear(), viewDate.getMonth(), 1);
  const daysInMonth = new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0).getDate();
  const startDay = monthStart.getDay();

  const handlePrevMonth = () => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1));
  const handleNextMonth = () => setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1));

  const days = Array.from({ length: daysInMonth }, (_, i) => {
    const d = new Date(viewDate.getFullYear(), viewDate.getMonth(), i + 1);
    const dateStr = d.toISOString().split('T')[0];
    const record = records.find(r => r.date === dateStr);
    return { date: dateStr, day: i + 1, record };
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDate) return;
    let finalRecord: AttendanceRecord = { employeeId: employee.id, date: selectedDate, status: formData.status as AttendanceStatus, notes: formData.notes || '' };
    if (formData.status === 'Duty' || formData.status === 'Half-Day') {
      if (formData.checkIn && formData.checkOut) {
        const total = calculateHours(formData.checkIn, formData.checkOut);
        finalRecord = { ...finalRecord, checkIn: formData.checkIn, checkOut: formData.checkOut, totalHours: total, otHours: getOT(total, employee.dailyWorkHours) };
      }
    }
    onAddRecord(finalRecord);
    setShowForm(false);
  };

  const openForm = (date: string, existing?: AttendanceRecord) => {
    setSelectedDate(date);
    setFormData(existing ? { ...existing } : { status: 'Duty', checkIn: '09:00', checkOut: '17:30', notes: '' });
    setShowForm(true);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center glass p-4 rounded-2xl border border-white/5">
        <h2 className="text-xl font-bold font-heading">{viewDate.toLocaleString('default', { month: 'long', year: 'numeric' })}</h2>
        <div className="flex space-x-2">
          <button onClick={handlePrevMonth} className="p-2 hover:bg-white/10 rounded-full"><ChevronLeft size={20} /></button>
          <button onClick={handleNextMonth} className="p-2 hover:bg-white/10 rounded-full"><ChevronRight size={20} /></button>
        </div>
      </div>
      <div className="grid grid-cols-7 gap-1">
        {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map(d => <div key={d} className="text-center text-[10px] font-bold text-slate-500 py-2">{d}</div>)}
        {Array.from({ length: startDay }).map((_, i) => <div key={`empty-${i}`} />)}
        {days.map(({ date, day, record }) => (
          <button key={date} onClick={() => openForm(date, record)} className={`aspect-square glass rounded-xl flex flex-col items-center justify-center relative transition-all border border-white/5 ${record ? 'bg-sky-500/5 shadow-inner' : ''}`}>
            <span className={`text-xs ${record ? 'text-sky-400 font-bold' : 'text-slate-500'}`}>{day}</span>
            {record && <div className={`mt-1 h-1 w-1 rounded-full ${STATUS_CONFIG[record.status].bg.replace('/20', '')}`} />}
          </button>
        ))}
      </div>
      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setShowForm(false)} />
          <form onSubmit={handleSubmit} className="relative w-full max-w-md glass p-6 rounded-3xl border border-sky-500/30 space-y-4">
            <div className="flex justify-between items-center"><h3 className="text-xl font-bold">Edit Day Log</h3><button type="button" onClick={() => setShowForm(false)} className="text-slate-400"><X size={24} /></button></div>
            <div className="grid grid-cols-3 gap-2">
              {(Object.keys(STATUS_CONFIG) as AttendanceStatus[]).map(s => (
                <button key={s} type="button" onClick={() => setFormData({...formData, status: s})} className={`py-2 text-[10px] rounded-lg border font-bold ${formData.status === s ? 'border-sky-500 bg-sky-500/20 text-sky-400' : 'border-white/5 bg-white/5 text-slate-400'}`}>{s}</button>
              ))}
            </div>
            {(formData.status === 'Duty' || formData.status === 'Half-Day') && (
              <div className="grid grid-cols-2 gap-4">
                <input type="time" value={formData.checkIn} onChange={e => setFormData({...formData, checkIn: e.target.value})} className="bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
                <input type="time" value={formData.checkOut} onChange={e => setFormData({...formData, checkOut: e.target.value})} className="bg-slate-900 border border-white/10 rounded-lg px-3 py-2" />
              </div>
            )}
            <textarea value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-lg px-3 py-2 h-20" placeholder="Notes..." />
            <div className="flex gap-2">
              <button type="submit" className="flex-1 py-3 bg-sky-500 rounded-xl font-bold">Update Record</button>
              {selectedDate && records.some(r => r.date === selectedDate) && <button type="button" onClick={() => { onDeleteRecord(selectedDate); setShowForm(false); }} className="p-3 bg-rose-500/20 text-rose-500 rounded-xl"><Trash2 size={24}/></button>}
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default Calendar;

import React, { useState } from 'react';
import { AttendanceRecord, Employee } from '../types';
import { Download, FileText, Calendar, Wallet } from 'lucide-react';
import { calculateSalary, downloadCSV } from '../utils';

interface Props {
  employee: Employee;
  records: AttendanceRecord[];
}

const Reports: React.FC<Props> = ({ employee, records }) => {
  const [selectedMonth, setSelectedMonth] = useState(new Date().toISOString().slice(0, 7));
  const monthlyRecords = records.filter(r => r.date.startsWith(selectedMonth)).sort((a,b) => a.date.localeCompare(b.date));
  const stats = calculateSalary(monthlyRecords, employee);

  const exportMonthly = () => {
    let csv = `Employee: ${employee.name},Month: ${selectedMonth}\n`;
    csv += "Date,Status,In,Out,Hours,OT,Notes\n";
    monthlyRecords.forEach(r => {
      csv += `${r.date},${r.status},${r.checkIn || ''},${r.checkOut || ''},${r.totalHours || 0},${r.otHours || 0},"${r.notes || ''}"\n`;
    });
    downloadCSV(csv, `${employee.name}_Report_${selectedMonth}.csv`);
  };

  return (
    <div className="space-y-6">
      <div className="glass p-6 rounded-3xl border border-white/5 flex flex-col md:flex-row justify-between items-center gap-4">
        <div><h2 className="text-2xl font-bold">Statements</h2><p className="text-slate-500 text-sm">{employee.name} • Monthly Report</p></div>
        <input type="month" value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="bg-slate-900 border border-white/10 rounded-xl px-4 py-2" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <button onClick={exportMonthly} className="glass p-6 rounded-3xl border border-white/5 hover:border-sky-500/50 flex items-center justify-between group">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-sky-500/10 rounded-xl"><FileText className="text-sky-400" /></div>
            <div className="text-left"><h4 className="font-bold">Download CSV</h4><p className="text-[10px] text-slate-500 font-bold uppercase">{monthlyRecords.length} records</p></div>
          </div>
          <Download size={20} className="text-slate-600 group-hover:text-sky-400" />
        </button>
        <div className="glass p-6 rounded-3xl border border-white/5 flex items-center gap-4">
          <div className="p-3 bg-emerald-500/10 rounded-xl"><Wallet className="text-emerald-400" /></div>
          <div><h4 className="font-bold text-emerald-400">₹{Math.round(stats.netSalary).toLocaleString()}</h4><p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Net Payable</p></div>
        </div>
      </div>

      <div className="glass rounded-3xl border border-white/5 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-xs">
            <thead className="bg-white/5 font-bold text-slate-400 uppercase tracking-tighter">
              <tr><th className="px-6 py-4">Date</th><th className="px-6 py-4">Status</th><th className="px-6 py-4">Hrs</th><th className="px-6 py-4">OT</th><th className="px-6 py-4">Notes</th></tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {monthlyRecords.length > 0 ? monthlyRecords.map(r => (
                <tr key={r.date} className="hover:bg-white/5">
                  <td className="px-6 py-4 font-mono">{r.date}</td>
                  <td className="px-6 py-4"><span className={`px-2 py-0.5 rounded text-[10px] font-bold ${r.status === 'Duty' ? 'text-emerald-400 bg-emerald-500/10' : 'text-rose-400 bg-rose-500/10'}`}>{r.status}</span></td>
                  <td className="px-6 py-4">{r.totalHours || '-'}</td>
                  <td className="px-6 py-4 text-amber-400">{r.otHours || '-'}</td>
                  <td className="px-6 py-4 text-slate-500 max-w-xs truncate">{r.notes}</td>
                </tr>
              )) : <tr><td colSpan={5} className="px-6 py-12 text-center text-slate-500 italic">No records for this period.</td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Reports;

export type AttendanceStatus = 'Duty' | 'SL' | 'PL' | 'CL' | 'Unpaid' | 'Half-Day' | 'Weekly Off' | 'Holiday' | 'Absent';
export type LeaveRequestStatus = 'Pending' | 'Approved' | 'Rejected';

export interface LeaveQuotas {
  SL: number;
  PL: number;
  CL: number;
}

export interface Employee {
  id: string;
  name: string;
  monthlySalary: number;
  otRate: number;
  dailyWorkHours: number;
  quotas: LeaveQuotas;
  role: string;
  joinedDate: string;
}

export interface AttendanceRecord {
  employeeId: string;
  date: string; // ISO format
  checkIn?: string; // HH:mm
  checkOut?: string; // HH:mm
  status: AttendanceStatus;
  notes: string;
  totalHours?: number;
  otHours?: number;
}

export interface LeaveRequest {
  id: string;
  employeeId: string;
  type: 'SL' | 'PL' | 'CL';
  startDate: string;
  endDate: string;
  reason: string;
  status: LeaveRequestStatus;
  createdAt: string;
}

/* Updated UserSettings to match the implementation in SettingsView */
export interface UserSettings {
  monthlySalary: number;
  otRate: number;
  dailyWorkHours: number;
  quotas: LeaveQuotas;
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar as CalendarIcon, 
  ClipboardList, 
  Settings as SettingsIcon,
  Sun,
  Moon,
  Clock,
  Download,
  Users,
  MessageSquare
} from 'lucide-react';
import { AttendanceRecord, Employee, LeaveRequest, AttendanceStatus, UserSettings } from './types';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar';
import LeaveManager from './components/LeaveManager';
import SettingsView from './components/SettingsView';
import Reports from './components/Reports';
import StaffManager from './components/StaffManager';
import LeaveApproval from './components/LeaveApproval';
import { calculateSalary } from './utils';

const EMPLOYEES_KEY = 'neon_employees_v2';
const RECORDS_KEY = 'neon_records_v2';
const LEAVES_KEY = 'neon_leaves_v2';
const SETTINGS_KEY = 'neon_settings_v2';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'leaves' | 'settings' | 'reports' | 'staff' | 'approvals'>('dashboard');
  const [darkMode, setDarkMode] = useState(true);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [selectedEmployeeId, setSelectedEmployeeId] = useState<string | null>(null);

  /* Initialize global app settings */
  const [settings, setSettings] = useState<UserSettings>({
    monthlySalary: 30000,
    otRate: 200,
    dailyWorkHours: 8.5,
    quotas: { SL: 12, PL: 15, CL: 10 }
  });

  // Load data
  useEffect(() => {
    const savedEmployees = localStorage.getItem(EMPLOYEES_KEY);
    const savedRecords = localStorage.getItem(RECORDS_KEY);
    const savedLeaves = localStorage.getItem(LEAVES_KEY);
    const savedSettings = localStorage.getItem(SETTINGS_KEY);

    if (savedEmployees) {
      const parsed = JSON.parse(savedEmployees);
      setEmployees(parsed);
      if (parsed.length > 0) setSelectedEmployeeId(parsed[0].id);
    }
    if (savedRecords) setRecords(JSON.parse(savedRecords));
    if (savedLeaves) setLeaveRequests(JSON.parse(savedLeaves));
    if (savedSettings) setSettings(JSON.parse(savedSettings));
  }, []);

  // Save data
  useEffect(() => { localStorage.setItem(EMPLOYEES_KEY, JSON.stringify(employees)); }, [employees]);
  useEffect(() => { localStorage.setItem(RECORDS_KEY, JSON.stringify(records)); }, [records]);
  useEffect(() => { localStorage.setItem(LEAVES_KEY, JSON.stringify(leaveRequests)); }, [leaveRequests]);
  useEffect(() => { localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings)); }, [settings]);

  const selectedEmployee = useMemo(() => 
    employees.find(e => e.id === selectedEmployeeId) || (employees.length > 0 ? employees[0] : null), 
  [employees, selectedEmployeeId]);

  const stats = useMemo(() => {
    if (!selectedEmployee) return null;
    const currentMonth = new Date().toISOString().slice(0, 7);
    const monthlyRecords = records.filter(r => r.employeeId === selectedEmployee.id && r.date.startsWith(currentMonth));
    return calculateSalary(monthlyRecords, selectedEmployee);
  }, [records, selectedEmployee]);

  const addRecord = (record: AttendanceRecord) => {
    setRecords(prev => {
      const filtered = prev.filter(r => !(r.date === record.date && r.employeeId === record.employeeId));
      return [...filtered, record];
    });
  };

  const deleteRecord = (date: string, employeeId: string) => {
    setRecords(prev => prev.filter(r => !(r.date === date && r.employeeId === employeeId)));
  };

  const handleApproveLeave = (req: LeaveRequest) => {
    // 1. Update Request Status
    setLeaveRequests(prev => prev.map(l => l.id === req.id ? { ...l, status: 'Approved' } : l));

    // 2. Generate Attendance Records for each day in range
    const start = new Date(req.startDate);
    const end = new Date(req.endDate);
    const newRecords: AttendanceRecord[] = [];

    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      newRecords.push({
        employeeId: req.employeeId,
        date: d.toISOString().split('T')[0],
        status: req.type as AttendanceStatus,
        notes: `Approved Leave Request: ${req.reason}`
      });
    }

    setRecords(prev => {
      const filtered = prev.filter(r => 
        !(r.employeeId === req.employeeId && r.date >= req.startDate && r.date <= req.endDate)
      );
      return [...filtered, ...newRecords];
    });
  };

  const handleRejectLeave = (id: string) => {
    setLeaveRequests(prev => prev.map(l => l.id === id ? { ...l, status: 'Rejected' } : l));
  };

  const NavItem = ({ id, icon: Icon, label }: { id: typeof activeTab, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center space-y-1 w-full py-2 transition-all min-w-[64px] ${
        activeTab === id ? 'text-sky-400 neon-text' : 'text-slate-400 hover:text-slate-200'
      }`}
    >
      <Icon size={20} />
      <span className="text-[9px] font-medium uppercase tracking-wider">{label}</span>
    </button>
  );

  return (
    <div className={`min-h-screen ${darkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'} pb-24`}>
      <header className="sticky top-0 z-50 glass border-b border-white/10 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 rounded-xl bg-sky-500 flex items-center justify-center shadow-lg shadow-sky-500/30">
            <Clock className="text-white" size={24} />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-xl font-bold leading-none">NeonStaff</h1>
            <p className="text-[10px] uppercase text-sky-400 tracking-widest font-bold">Manager Mode</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {employees.length > 0 && (
            <div className="flex items-center gap-2">
              <span className="text-[10px] uppercase font-bold text-slate-500 hidden md:block">Active:</span>
              <select 
                value={selectedEmployeeId || ''} 
                onChange={(e) => setSelectedEmployeeId(e.target.value)}
                className="bg-slate-900 border border-white/10 rounded-lg px-3 py-1.5 text-xs text-sky-400 font-bold focus:outline-none focus:ring-1 focus:ring-sky-500 transition-all"
              >
                {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
              </select>
            </div>
          )}
          <button 
            onClick={() => setDarkMode(!darkMode)}
            className="p-2 rounded-full glass border border-white/10 hover:bg-white/10 transition-colors"
          >
            {darkMode ? <Sun size={20} className="text-amber-400" /> : <Moon size={20} className="text-slate-600" />}
          </button>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 md:p-6">
        {employees.length === 0 && activeTab !== 'staff' ? (
          <div className="text-center py-20 space-y-6 animate-in fade-in duration-700">
            <div className="w-24 h-24 bg-slate-900 rounded-full flex items-center justify-center mx-auto border border-white/5">
               <Users size={48} className="text-slate-700" />
            </div>
            <div className="space-y-2">
              <h2 className="text-3xl font-bold">No Staff Members</h2>
              <p className="text-slate-500">You haven't added any employees to the system yet.</p>
            </div>
            <button 
              onClick={() => setActiveTab('staff')} 
              className="px-8 py-3 bg-sky-500 rounded-xl font-bold shadow-lg shadow-sky-500/20 hover:scale-105 transition-transform"
            >
              Setup Staff Directory
            </button>
          </div>
        ) : (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            {activeTab === 'dashboard' && selectedEmployee && (
              <Dashboard 
                stats={stats} 
                employee={selectedEmployee} 
                records={records} 
                onAddRecord={addRecord} 
              />
            )}
            {activeTab === 'staff' && (
              <StaffManager 
                employees={employees} 
                onAdd={(e) => {
                  setEmployees([...employees, e]);
                  if (employees.length === 0) setSelectedEmployeeId(e.id);
                }} 
                onUpdate={(e) => setEmployees(employees.map(emp => emp.id === e.id ? e : emp))} 
                onDelete={(id) => {
                  setEmployees(employees.filter(e => e.id !== id));
                  if (selectedEmployeeId === id) setSelectedEmployeeId(employees.find(e => e.id !== id)?.id || null);
                }} 
              />
            )}
            {activeTab === 'calendar' && selectedEmployee && (
              <Calendar 
                employee={selectedEmployee} 
                records={records.filter(r => r.employeeId === selectedEmployee.id)} 
                onAddRecord={addRecord} 
                onDeleteRecord={(d) => deleteRecord(d, selectedEmployee.id)} 
              />
            )}
            {activeTab === 'approvals' && (
              <LeaveApproval 
                requests={leaveRequests} 
