            {activeTab === 'leaves' && selectedEmployee && (
              <LeaveManager 
                employee={selectedEmployee} 
                records={records.filter(r => r.employeeId === selectedEmployee.id)} 
                leaveRequests={leaveRequests.filter(l => l.employeeId === selectedEmployee.id)} 
