                  {/* Required Section */}
                  <div className="space-y-3">
                    <h4 className="text-[10px] font-bold text-sky-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <CheckCircle2 size={14} /> Required Column Mapping
