                            <span className="text-sm font-medium">{field.label}</span>
                          </div>
                          <select 
                            value={mapping[field.id] || ''}
                            onChange={(e) => setMapping({...mapping, [field.id]: e.target.value})}
                            className="flex-1 bg-slate-950 border border-white/10 rounded-xl px-3 py-2 text-xs focus:outline-none focus:border-sky-500"
