                            <option value="">-- Select CSV Column --</option>
                            {csvHeaders.map(h => <option key={h} value={h}>{h}</option>)}
                          </select>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Optional Section */}
                  <div className="space-y-3">
                    <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-[0.2em] flex items-center gap-2">
                      <Plus size={14} /> Optional Data Mapping
                    </h4>
                    <div className="grid grid-cols-1 gap-3">
                      {optionalFields.map(field => (
                        <div key={field.id} className="flex items-center gap-4 bg-slate-900/30 p-3 rounded-2xl border border-white/5">
                          <div className="w-1/3 flex items-center gap-2">
                            <span className="text-xs font-medium text-slate-400">{field.label}</span>
                          </div>
                          <select 
                            value={mapping[field.id] || ''}
