                  >
                    Back to Selection
                  </button>
                  <button 
                    onClick={executeImport}
                    disabled={!mapping['name']}
                    className={`flex-2 py-3 bg-emerald-500 hover:bg-emerald-600 rounded-xl font-bold shadow-lg shadow-emerald-500/20 transition-all ${!mapping['name'] ? 'opacity-50 grayscale cursor-not-allowed' : ''}`}
                  >
                    Import {csvRows.length} Employees
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffManager;

export type AttendanceStatus = 'Duty' | 'SL' | 'PL' | 'CL' | 'Unpaid' | 'Half-Day' | 'Weekly Off' | 'Holiday' | 'Absent';
export type LeaveRequestStatus = 'Pending' | 'Approved' | 'Rejected';

export interface User {
  id: string;
  username: string;
  fullName: string;
  age: number;
  gender: string;
  occupation?: string;
  provider: 'google' | 'facebook' | 'apple' | 'email' | 'phone' | 'credentials';
}

export interface LeaveQuotas {
  SL: number;
  PL: number;
  CL: number;
}

export interface Employee {
  id: string;
  name: string;
  monthlySalary: number;
  otRate: number;
  dailyWorkHours: number;
  quotas: LeaveQuotas;
  role: string;
  joinedDate: string;
  notes?: string;
}

export interface AttendanceRecord {
  employeeId: string;
  date: string; // ISO format
  checkIn?: string; // HH:mm
  checkOut?: string; // HH:mm
  status: AttendanceStatus;
  notes: string;
  totalHours?: number;
  otHours?: number;
}

export interface LeaveRequest {
  id: string;
  employeeId: string;
  type: 'SL' | 'PL' | 'CL';
  startDate: string;
  endDate: string;
  reason: string;
  status: LeaveRequestStatus;
  createdAt: string;
}

export interface UserSettings {
  monthlySalary: number;
  otRate: number;
  dailyWorkHours: number;
  quotas: LeaveQuotas;
}

import React, { useState } from 'react';
import { User } from '../types';
import { 
  LogIn, 
  User as UserIcon, 
  Lock, 
  Mail, 
  Phone, 
  Github, 
  Chrome, 
  Facebook, 
  Apple, 
  ShieldCheck,
  ChevronRight,
  ArrowLeft
} from 'lucide-react';

interface Props {
  onLogin: (user: User) => void;
}

type AuthStep = 'initial' | 'setup' | 'credentials';

const AuthView: React.FC<Props> = ({ onLogin }) => {
  const [step, setStep] = useState<AuthStep>('initial');
  const [provider, setProvider] = useState<User['provider']>('google');

  const [formData, setFormData] = useState({
    username: '',
    password: '',
    fullName: '',
    age: '',
    gender: 'Other',
    occupation: ''
  });

  const handleSocialClick = (p: User['provider']) => {
    setProvider(p);
    // Simulate checking if user exists in DB
    const users = JSON.parse(localStorage.getItem('attendify_auth_users') || '[]');
    const existing = users.find((u: any) => u.provider === p);

    if (existing) {
      onLogin(existing);
    } else {
      setStep('setup');
    }
  };

  const handleCredentialLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const users = JSON.parse(localStorage.getItem('attendify_auth_users') || '[]');
    const user = users.find((u: any) => u.username === formData.username && u.password === formData.password);

    if (user) {
      onLogin(user);
    } else {
      alert("Invalid credentials. Please use social login or check your username.");
    }
  };

  const handleSetupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newUser: User & { password?: string } = {
      id: Date.now().toString(),
      username: formData.username,
      fullName: formData.fullName,
      age: parseInt(formData.age),
      gender: formData.gender,
      occupation: formData.occupation,
      provider: provider,
      password: formData.password // Storing password for demo purposes
    };

    const users = JSON.parse(localStorage.getItem('attendify_auth_users') || '[]');
    // Check if username taken
    if (users.some((u: any) => u.username === formData.username)) {
      alert("Username already taken!");
      return;
    }

    users.push(newUser);
    localStorage.setItem('attendify_auth_users', JSON.stringify(users));
    onLogin(newUser);
  };

  const SocialButton = ({ icon: Icon, label, color, provider: p }: any) => (
    <button 
      onClick={() => handleSocialClick(p)}
      className="w-full flex items-center gap-4 p-4 rounded-2xl glass border border-white/5 hover:border-sky-500/50 hover:bg-sky-500/5 transition-all group"
    >
      <div className={`p-2 rounded-xl bg-${color}-500/10 text-${color}-400 group-hover:scale-110 transition-transform`}>
        <Icon size={24} />
      </div>
      <span className="font-bold text-slate-300">Continue with {label}</span>
      <ChevronRight className="ml-auto text-slate-600 group-hover:text-sky-400" size={18} />
    </button>
  );

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950 relative overflow-hidden">
      {/* Decorative background elements */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-sky-500/10 blur-[120px] rounded-full" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-500/10 blur-[120px] rounded-full" />

      <div className="w-full max-w-md relative z-10">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-sky-500 rounded-[2rem] flex items-center justify-center shadow-2xl shadow-sky-500/30 mx-auto mb-6 rotate-3">
            <ShieldCheck size={40} className="text-white" />
          </div>
          <h1 className="text-4xl font-black font-heading mb-2 tracking-tight">Attendify</h1>
          <p className="text-slate-500 font-medium">Smart Attendance & Salary Management</p>
        </div>

        {step === 'initial' && (
          <div className="space-y-4 animate-in fade-in slide-in-from-bottom-6 duration-500">
            <SocialButton icon={Chrome} label="Google" color="rose" provider="google" />
            <SocialButton icon={Facebook} label="Facebook" color="blue" provider="facebook" />
            <SocialButton icon={Apple} label="Apple" color="slate" provider="apple" />

            <div className="flex items-center gap-4 my-8">
              <div className="flex-1 h-px bg-white/10" />
              <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest">or use credentials</span>
              <div className="flex-1 h-px bg-white/10" />
            </div>

            <button 
              onClick={() => setStep('credentials')}
              className="w-full p-4 rounded-2xl glass border border-white/5 hover:border-sky-500/50 hover:bg-sky-500/5 transition-all flex items-center justify-center gap-3 font-bold text-sky-400"
            >
              <LogIn size={20} /> Login with Username
            </button>
          </div>
        )}

        {step === 'credentials' && (
          <form onSubmit={handleCredentialLogin} className="glass p-8 rounded-[2.5rem] border border-white/5 space-y-6 animate-in fade-in zoom-in duration-300">
             <button onClick={() => setStep('initial')} className="flex items-center gap-2 text-slate-500 hover:text-white transition-colors text-xs font-bold uppercase tracking-widest mb-4">
              <ArrowLeft size={14} /> Back
