            <div className="space-y-1">
              <h2 className="text-2xl font-bold font-heading">Complete Profile</h2>
              <p className="text-slate-500 text-xs">Finalize your account details to continue</p>
            </div>

            <div className="grid grid-cols-1 gap-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
