                  <input required value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3" placeholder="johndoe123" />
                </div>
                <div className="space-y-1.5">
