              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Occupation (Optional)</label>
                <input value={formData.occupation} onChange={e => setFormData({...formData, occupation: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3" placeholder="e.g. Project Manager" />
              </div>
            </div>

            <button type="submit" className="w-full py-4 bg-emerald-500 hover:bg-emerald-600 text-white font-bold rounded-2xl shadow-xl shadow-emerald-500/20 transition-all mt-4">
              Finish Setup
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

