import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar as CalendarIcon, 
  ClipboardList, 
  Settings as SettingsIcon,
  Sun,
  Moon,
  Clock,
  Download,
  Users,
  MessageSquare,
  LogOut,
  User as UserIcon,
  ShieldCheck
} from 'lucide-react';
import { AttendanceRecord, Employee, LeaveRequest, AttendanceStatus, UserSettings, User } from './types';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar';
import LeaveManager from './components/LeaveManager';
import SettingsView from './components/SettingsView';
import Reports from './components/Reports';
import StaffManager from './components/StaffManager';
import LeaveApproval from './components/LeaveApproval';
import AuthView from './components/AuthView';
import { calculateSalary } from './utils';

const EMPLOYEES_KEY = 'neon_employees_v2';
const RECORDS_KEY = 'neon_records_v2';
const LEAVES_KEY = 'neon_leaves_v2';
const SETTINGS_KEY = 'neon_settings_v2';
const AUTH_SESSION_KEY = 'neon_user_session';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'leaves' | 'settings' | 'reports' | 'staff' | 'approvals'>('dashboard');

  // App Data State
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    monthlySalary: 30000,
    otRate: 200,
    dailyWorkHours: 8.5,
    quotas: { SL: 12, PL: 15, CL: 10 }
  });

  // Load state from local storage
  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_SESSION_KEY);
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    const savedEmps = localStorage.getItem(EMPLOYEES_KEY);
    if (savedEmps) setEmployees(JSON.parse(savedEmps));

    const savedRecords = localStorage.getItem(RECORDS_KEY);
    if (savedRecords) setRecords(JSON.parse(savedRecords));

    const savedLeaves = localStorage.getItem(LEAVES_KEY);
    if (savedLeaves) setLeaveRequests(JSON.parse(savedLeaves));

    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) setSettings(JSON.parse(savedSettings));
  }, []);

  // Persist state
  useEffect(() => {
    localStorage.setItem(EMPLOYEES_KEY, JSON.stringify(employees));
  }, [employees]);

  useEffect(() => {
    localStorage.setItem(RECORDS_KEY, JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem(LEAVES_KEY, JSON.stringify(leaveRequests));
  }, [leaveRequests]);

  useEffect(() => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [settings]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem(AUTH_SESSION_KEY, JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_SESSION_KEY);
  };

  // Logic to determine which employee is "The User" for the dashboard
  // In a real app, this would be linked to the Auth User ID
  const activeEmployee = useMemo(() => {
    if (employees.length === 0) return null;
    // Fallback: search for employee matching auth full name or just use the first one
    return employees.find(e => e.name === currentUser?.fullName) || employees[0];
  }, [employees, currentUser]);

  const stats = useMemo(() => {
    if (!activeEmployee) return null;
    const monthlyRecords = records.filter(r => 
      r.employeeId === activeEmployee.id && 
      r.date.startsWith(new Date().toISOString().slice(0, 7))
    );
    return calculateSalary(monthlyRecords, activeEmployee);
  }, [records, activeEmployee]);

  if (!currentUser) {
    return <AuthView onLogin={handleLogin} />;
  }

  const NavItem = ({ id, icon: Icon, label }: any) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex items-center gap-3 px-4 py-3 rounded-2xl transition-all duration-300 ${
        activeTab === id 
          ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/30 font-bold' 
          : 'text-slate-400 hover:text-white hover:bg-white/5'
      }`}
    >
      <Icon size={20} />
      <span className="hidden md:block text-sm">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#0f172a] text-slate-100">
      {/* Sidebar */}
      <aside className="w-full md:w-64 glass-dark border-r border-white/5 p-6 flex flex-col gap-8 z-50">
        <div className="flex items-center gap-3 px-2">
          <div className="p-2 bg-sky-500 rounded-xl shadow-lg shadow-sky-500/20">
            <ShieldCheck className="text-white" size={24} />
          </div>
          <h1 className="text-2xl font-black font-heading tracking-tight">Attendify</h1>
        </div>

        <nav className="flex flex-row md:flex-col gap-2 overflow-x-auto md:overflow-visible pb-4 md:pb-0 scrollbar-hide">
          <NavItem id="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem id="calendar" icon={CalendarIcon} label="Attendance" />
          <NavItem id="leaves" icon={ClipboardList} label="Leave Center" />
          <NavItem id="reports" icon={Download} label="Reports" />
          <div className="h-px bg-white/5 my-2 hidden md:block" />
          <NavItem id="staff" icon={Users} label="Staff Manager" />
          <NavItem id="approvals" icon={MessageSquare} label="Approvals" />
          <NavItem id="settings" icon={SettingsIcon} label="Settings" />
        </nav>

        <div className="mt-auto hidden md:block">
          <div className="glass p-4 rounded-2xl border border-white/5 flex items-center gap-3 mb-4">
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-sky-400 to-blue-600 flex items-center justify-center font-bold">
              {currentUser.fullName.charAt(0)}
            </div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold truncate">{currentUser.fullName}</p>
              <p className="text-[10px] text-slate-500 truncate">@{currentUser.username}</p>
            </div>
          </div>
          <button 
            onClick={handleLogout}
            className="w-full flex items-center gap-3 px-4 py-3 rounded-2xl text-rose-500 hover:bg-rose-500/10 transition-all font-bold text-sm"
          >
            <LogOut size={18} /> Logout
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-4 md:p-8 overflow-y-auto max-h-screen custom-scrollbar">
        <div className="max-w-5xl mx-auto pb-20 md:pb-0">
          {activeEmployee ? (
            <>
              {activeTab === 'dashboard' && stats && (
                <Dashboard 
                  stats={stats} 
                  employee={activeEmployee} 
                  records={records} 
                  onAddRecord={(r) => {
                    const filtered = records.filter(rec => !(rec.date === r.date && rec.employeeId === r.employeeId));
                    setRecords([...filtered, r]);
                  }} 
                />
              )}
              {activeTab === 'calendar' && (
                <Calendar 
                  employee={activeEmployee} 
                  records={records.filter(r => r.employeeId === activeEmployee.id)}
                  onAddRecord={(r) => {
                    const filtered = records.filter(rec => !(rec.date === r.date && rec.employeeId === r.employeeId));
                    setRecords([...filtered, r]);
                  }}
                  onDeleteRecord={(date) => {
                    setRecords(records.filter(r => !(r.date === date && r.employeeId === activeEmployee.id)));
                  }}
                />
              )}
              {activeTab === 'leaves' && (
                <LeaveManager 
                  employee={activeEmployee}
                  records={records.filter(r => r.employeeId === activeEmployee.id)}
                  leaveRequests={leaveRequests.filter(l => l.employeeId === activeEmployee.id)}
                  onAddRequest={(r) => setLeaveRequests([...leaveRequests, r])}
                />
              )}
              {activeTab === 'reports' && (
                <Reports 
                  employee={activeEmployee} 
                  records={records.filter(r => r.employeeId === activeEmployee.id)} 
                />
              )}
            </>
          ) : (
            <div className="glass p-12 text-center rounded-[3rem] border border-sky-500/20">
              <Users size={48} className="mx-auto text-sky-400 mb-4 opacity-50" />
              <h2 className="text-2xl font-bold mb-2">No Active Profile</h2>
              <p className="text-slate-500 mb-6">You need to register yourself as an employee to see the dashboard.</p>
              <button 
                onClick={() => setActiveTab('staff')}
                className="bg-sky-500 px-8 py-3 rounded-2xl font-bold shadow-xl shadow-sky-500/20"
              >
                Go to Staff Manager
              </button>
            </div>
          )}

          {activeTab === 'staff' && (
            <StaffManager 
              employees={employees}
              onAdd={(e) => setEmployees([...employees, e])}
              onUpdate={(e) => setEmployees(employees.map(emp => emp.id === e.id ? e : emp))}
              onDelete={(id) => setEmployees(employees.filter(e => e.id !== id))}
            />
          )}

          {activeTab === 'approvals' && (
            <LeaveApproval 
              requests={leaveRequests}
              employees={employees}
              onApprove={(req) => {
                // Update request status
                setLeaveRequests(leaveRequests.map(l => l.id === req.id ? { ...l, status: 'Approved' } : l));
                // Add attendance records for all dates in range
                const start = new Date(req.startDate);
                const end = new Date(req.endDate);
                const newRecords: AttendanceRecord[] = [];
                for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
                  const dateStr = d.toISOString().split('T')[0];
                  newRecords.push({
                    employeeId: req.employeeId,
                    date: dateStr,
                    status: req.type,
                    notes: `Approved Leave: ${req.reason}`
                  });
                }
                // Filter out existing records for these dates to avoid duplicates
                const filteredRecords = records.filter(r => 
                  !(r.employeeId === req.employeeId && newRecords.some(nr => nr.date === r.date))
                );
                setRecords([...filteredRecords, ...newRecords]);
              }}
              onReject={(id) => setLeaveRequests(leaveRequests.map(l => l.id === id ? { ...l, status: 'Rejected' } : l))}
            />
          )}

          {activeTab === 'settings' && (
            <SettingsView 
              settings={settings}
              onSave={setSettings}
            />
          )}
        </div>
      </main>

      {/* Mobile Profile/Logout Footer */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 glass-dark border-t border-white/5 p-4 flex justify-between items-center z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-sky-500 flex items-center justify-center font-bold text-xs">
            {currentUser.fullName.charAt(0)}
          </div>
          <span className="text-xs font-bold truncate max-w-[100px]">{currentUser.fullName}</span>
        </div>
        <button onClick={handleLogout} className="text-rose-500 text-xs font-bold flex items-center gap-1">
          <LogOut size={14} /> Logout
        </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Employee } from '../types';
import { 
  Plus, 
  User, 
  Edit2, 
  Trash2, 
  X, 
  ShieldCheck, 
  Wallet, 
  Clock, 
  Briefcase,
  CalendarDays,
  Info,
  Users,
  StickyNote,
  Upload,
  FileSpreadsheet,
  CheckCircle2,
  Calendar
} from 'lucide-react';

interface Props {
  employees: Employee[];
  onAdd: (e: Employee) => void;
  onUpdate: (e: Employee) => void;
  onDelete: (id: string) => void;
}

type ImportStep = 'select' | 'map' | 'preview';

const StaffManager: React.FC<Props> = ({ employees, onAdd, onUpdate, onDelete }) => {
  const [showModal, setShowModal] = useState(false);
  const [showImportModal, setShowImportModal] = useState(false);
  const [editingEmployee, setEditingEmployee] = useState<Employee | null>(null);

  // Import State
  const [importStep, setImportStep] = useState<ImportStep>('select');
  const [csvHeaders, setCsvHeaders] = useState<string[]>([]);
  const [csvRows, setCsvRows] = useState<string[][]>([]);
  const [mapping, setMapping] = useState<Record<string, string>>({});
  const fileInputRef = useRef<HTMLInputElement>(null);

  const getTodayStr = () => new Date().toISOString().split('T')[0];

  const [formData, setFormData] = useState({
    name: '',
    role: 'Staff Member',
    salary: 30000,
    otRate: 200,
    dailyHours: 8.5,
    sl: 12, pl: 15, cl: 10,
    notes: '',
    joinedDate: getTodayStr()
  });

  const resetForm = () => {
    setFormData({
      name: '',
      role: 'Staff Member',
      salary: 30000,
      otRate: 200,
      dailyHours: 8.5,
      sl: 12, pl: 15, cl: 10,
      notes: '',
      joinedDate: getTodayStr()
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newEmp: Employee = {
      id: editingEmployee?.id || Date.now().toString(),
      name: formData.name,
      role: formData.role,
      monthlySalary: formData.salary,
      otRate: formData.otRate,
      dailyWorkHours: formData.dailyHours,
      joinedDate: formData.joinedDate,
      quotas: { SL: formData.sl, PL: formData.pl, CL: formData.cl },
      notes: formData.notes
    };

    if (editingEmployee) onUpdate(newEmp);
    else onAdd(newEmp);

    setShowModal(false);
    setEditingEmployee(null);
    resetForm();
  };

  const handleEdit = (emp: Employee) => {
    setEditingEmployee(emp);
    setFormData({
      name: emp.name,
      role: emp.role,
      salary: emp.monthlySalary,
      otRate: emp.otRate,
      dailyHours: emp.dailyWorkHours,
      sl: emp.quotas.SL, pl: emp.quotas.PL, cl: emp.quotas.CL,
      notes: emp.notes || '',
      joinedDate: emp.joinedDate ? emp.joinedDate.split('T')[0] : getTodayStr()
    });
    setShowModal(true);
  };

  // CSV Processing Logic
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
      if (lines.length < 2) {
        alert("CSV file seems empty or lacks data.");
        return;
      }

      // Basic CSV parsing (handles quotes)
      const parseLine = (line: string) => {
        const result = [];
        let cur = '';
        let inQuotes = false;
        for (let i = 0; i < line.length; i++) {
          const char = line[i];
          if (char === '"') inQuotes = !inQuotes;
          else if (char === ',' && !inQuotes) {
            result.push(cur.trim());
            cur = '';
          } else {
            cur += char;
          }
        }
        result.push(cur.trim());
        return result;
      };

      const headers = parseLine(lines[0]);
      const rows = lines.slice(1).map(line => parseLine(line));

      setCsvHeaders(headers);
      setCsvRows(rows);

      // Auto-mapping logic (fuzzy match)
      const initialMapping: Record<string, string> = {};
      const fields = ['name', 'role', 'monthlySalary', 'otRate', 'dailyWorkHours', 'joinedDate', 'SL', 'PL', 'CL', 'notes'];

      fields.forEach(field => {
        const match = headers.find(h => 
          h.toLowerCase().includes(field.toLowerCase()) || 
          field.toLowerCase().includes(h.toLowerCase())
        );
        if (match) initialMapping[field] = match;
      });

      setMapping(initialMapping);
      setImportStep('map');
    };
    reader.readAsText(file);
  };

  const executeImport = () => {
    if (!mapping['name']) {
      alert("Please map at least the 'Name' field.");
      return;
    }

    csvRows.forEach((row, index) => {
      const getVal = (field: string) => {
        const header = mapping[field];
        if (!header) return undefined;
        const colIdx = csvHeaders.indexOf(header);
        return row[colIdx];
      };

      const name = getVal('name');
      if (!name) return;

      const newEmp: Employee = {
        id: `import-${Date.now()}-${index}`,
        name: name,
        role: getVal('role') || 'Staff Member',
        monthlySalary: Number(getVal('monthlySalary')) || 30000,
        otRate: Number(getVal('otRate')) || 200,
        dailyWorkHours: Number(getVal('dailyWorkHours')) || 8.5,
        joinedDate: getVal('joinedDate') || getTodayStr(),
        quotas: {
          SL: Number(getVal('SL')) || 12,
          PL: Number(getVal('PL')) || 15,
          CL: Number(getVal('CL')) || 10
        },
        notes: getVal('notes')
      };
      onAdd(newEmp);
    });

    setShowImportModal(false);
    setImportStep('select');
    setMapping({});
  };

  const requiredFields = [
    { id: 'name', label: 'Full Name', icon: <User size={12} /> },
    { id: 'monthlySalary', label: 'Monthly Salary', icon: <Wallet size={12} /> },
    { id: 'otRate', label: 'OT Rate', icon: <Clock size={12} /> },
    { id: 'dailyWorkHours', label: 'Duty Hours', icon: <Briefcase size={12} /> },
  ];

  const optionalFields = [
    { id: 'role', label: 'Designation' },
    { id: 'joinedDate', label: 'Joined Date' },
    { id: 'SL', label: 'Sick Leave (SL)' },
    { id: 'PL', label: 'Paid Leave (PL)' },
    { id: 'CL', label: 'Casual Leave (CL)' },
    { id: 'notes', label: 'Remarks / Notes' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold font-heading">Staff Directory</h2>
          <p className="text-slate-500 text-sm">Manage your team and their contracts</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => { setShowImportModal(true); setImportStep('select'); }}
            className="flex items-center gap-2 glass hover:bg-white/10 px-4 py-2.5 rounded-xl font-bold text-sm transition-all border border-white/10"
          >
            <Upload size={18} /> Import CSV
          </button>
          <button 
            onClick={() => { setShowModal(true); setEditingEmployee(null); resetForm(); }}
            className="flex items-center gap-2 bg-sky-500 hover:bg-sky-600 px-5 py-2.5 rounded-xl font-bold text-sm transition-all shadow-lg shadow-sky-500/30 active:scale-95"
          >
            <Plus size={18} /> Add New Employee
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {employees.length > 0 ? (
          employees.map(emp => (
            <div key={emp.id} className="glass p-5 rounded-3xl border border-white/5 flex items-center justify-between group hover:border-sky-500/30 transition-all shadow-xl">
              <div className="flex items-center gap-4">
                <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-slate-800 to-slate-900 flex items-center justify-center text-sky-400 border border-white/5 shadow-inner">
                  <User size={28} />
                </div>
                <div className="flex-1">
                  <h4 className="font-bold text-lg leading-tight">{emp.name}</h4>
                  <p className="text-[10px] text-slate-500 uppercase tracking-[0.2em] font-bold mt-1">{emp.role}</p>
                  <div className="flex items-center gap-3 mt-2">
                    <span className="text-[10px] bg-sky-500/10 text-sky-400 px-2 py-0.5 rounded border border-sky-500/10 font-bold">₹{emp.monthlySalary.toLocaleString()}</span>
                    <span className="text-[10px] bg-slate-500/10 text-slate-400 px-2 py-0.5 rounded border border-white/5 font-bold">{emp.dailyWorkHours} hrs/day</span>
                  </div>
                  <div className="flex items-center gap-2 mt-1">
                    <Calendar size={10} className="text-slate-500" />
                    <span className="text-[10px] text-slate-500 font-medium">Joined: {emp.joinedDate}</span>
                  </div>
                  {emp.notes && (
                    <div className="mt-2 text-[10px] text-slate-500 line-clamp-1 italic">
                      <StickyNote size={10} className="inline mr-1" /> {emp.notes}
                    </div>
                  )}
                </div>
              </div>
              <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
