          <div className="relative glass w-full max-w-xl p-8 rounded-[2rem] border border-sky-500/30 shadow-[0_0_50px_rgba(14,165,233,0.15)] animate-in zoom-in duration-300 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
