import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar as CalendarIcon, 
  ClipboardList, 
  Settings as SettingsIcon,
  Sun,
  Moon,
  Clock,
  Download,
  Users,
  MessageSquare,
  LogOut,
  User as UserIcon,
  ShieldCheck,
  ChevronRight
} from 'lucide-react';
import { AttendanceRecord, Employee, LeaveRequest, AttendanceStatus, UserSettings, User } from './types';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar';
import LeaveManager from './components/LeaveManager';
import SettingsView from './components/SettingsView';
import Reports from './components/Reports';
import StaffManager from './components/StaffManager';
import LeaveApproval from './components/LeaveApproval';
import AuthView from './components/AuthView';
import { calculateSalary } from './utils';

const EMPLOYEES_KEY = 'neon_employees_v2';
const RECORDS_KEY = 'neon_records_v2';
const LEAVES_KEY = 'neon_leaves_v2';
const SETTINGS_KEY = 'neon_settings_v2';
const AUTH_SESSION_KEY = 'neon_user_session';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'leaves' | 'settings' | 'reports' | 'staff' | 'approvals'>('dashboard');
  const [lastTab, setLastTab] = useState(activeTab);

  // App Data State
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    monthlySalary: 30000,
    otRate: 200,
    dailyWorkHours: 8.5,
    quotas: { SL: 12, PL: 15, CL: 10 }
  });

  // Load state from local storage
  useEffect(() => {
    const savedUser = localStorage.getItem(AUTH_SESSION_KEY);
    if (savedUser) setCurrentUser(JSON.parse(savedUser));

    const savedEmps = localStorage.getItem(EMPLOYEES_KEY);
    if (savedEmps) setEmployees(JSON.parse(savedEmps));

    const savedRecords = localStorage.getItem(RECORDS_KEY);
    if (savedRecords) setRecords(JSON.parse(savedRecords));

    const savedLeaves = localStorage.getItem(LEAVES_KEY);
    if (savedLeaves) setLeaveRequests(JSON.parse(savedLeaves));

    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) setSettings(JSON.parse(savedSettings));
  }, []);

  // Persist state
  useEffect(() => {
    localStorage.setItem(EMPLOYEES_KEY, JSON.stringify(employees));
  }, [employees]);

  useEffect(() => {
    localStorage.setItem(RECORDS_KEY, JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem(LEAVES_KEY, JSON.stringify(leaveRequests));
  }, [leaveRequests]);

  useEffect(() => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [settings]);

  // Track tab changes for animation
  useEffect(() => {
    if (activeTab !== lastTab) {
      setLastTab(activeTab);
    }
  }, [activeTab]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem(AUTH_SESSION_KEY, JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_SESSION_KEY);
  };

  const activeEmployee = useMemo(() => {
    if (employees.length === 0) return null;
    return employees.find(e => e.name === currentUser?.fullName) || employees[0];
  }, [employees, currentUser]);

  const stats = useMemo(() => {
    if (!activeEmployee) return null;
    const monthlyRecords = records.filter(r => 
      r.employeeId === activeEmployee.id && 
      r.date.startsWith(new Date().toISOString().slice(0, 7))
    );
    return calculateSalary(monthlyRecords, activeEmployee);
  }, [records, activeEmployee]);

  if (!currentUser) {
    return <AuthView onLogin={handleLogin} />;
  }

  const NavItem = ({ id, icon: Icon, label }: any) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex items-center gap-3 px-4 py-3 rounded-2xl transition-all duration-300 ${
        activeTab === id 
          ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/30 font-bold' 
          : 'text-slate-400 hover:text-white hover:bg-white/5'
      }`}
    >
      <Icon size={20} />
      <span className="hidden md:block text-sm">{label}</span>
    </button>
  );

  const tabLabels: Record<string, string> = {
    dashboard: 'Dashboard',
    calendar: 'Attendance Log',
    leaves: 'Leave Center',
    reports: 'Monthly Reports',
    staff: 'Staff Directory',
    approvals: 'Admin Approvals',
    settings: 'App Settings'
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#0f172a] text-slate-100">
      {/* Sidebar */}
      <aside className="w-full md:w-64 glass-dark border-r border-white/5 p-6 flex flex-col gap-8 z-50">
        <div className="flex items-center gap-3 px-2">
          <div className="p-2 bg-sky-500 rounded-xl shadow-lg shadow-sky-500/20">
            <ShieldCheck className="text-white" size={24} />
          </div>
          <h1 className="text-2xl font-black font-heading tracking-tight">Attendify</h1>
        </div>

        <nav className="flex flex-row md:flex-col gap-2 overflow-x-auto md:overflow-visible pb-4 md:pb-0 scrollbar-hide">
          <NavItem id="dashboard" icon={LayoutDashboard} label="Dashboard" />
          <NavItem id="calendar" icon={CalendarIcon} label="Attendance" />
          <NavItem id="leaves" icon={ClipboardList} label="Leave Center" />
          <NavItem id="reports" icon={Download} label="Reports" />
          <div className="h-px bg-white/5 my-2 hidden md:block" />
          <NavItem id="staff" icon={Users} label="Staff Manager" />
          <NavItem id="approvals" icon={MessageSquare} label="Approvals" />
          <NavItem id="settings" icon={SettingsIcon} label="Settings" />
        </nav>
      </aside>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col relative overflow-hidden">
        {/* Top Header */}
        <header className="sticky top-0 z-40 glass border-b border-white/5 px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-4 overflow-hidden">
            {/* Animated Tab Indicator Text */}
            <div key={activeTab} className="animate-in slide-in-from-bottom-2 fade-in duration-300">
               <h2 className="text-xl font-bold font-heading text-sky-400 neon-text">
                {tabLabels[activeTab]}
              </h2>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden sm:flex items-center gap-3 glass border border-white/10 px-3 py-1.5 rounded-2xl">
              <div className="w-8 h-8 rounded-full bg-gradient-to-br from-sky-400 to-blue-600 flex items-center justify-center font-bold text-xs">
                {currentUser.fullName.charAt(0)}
              </div>
              <div className="flex flex-col">
                <span className="text-[10px] font-bold leading-tight">{currentUser.fullName}</span>
                <span className="text-[8px] text-slate-500 font-bold uppercase tracking-wider">@{currentUser.username}</span>
              </div>
            </div>

            <button 
              onClick={handleLogout}
              className="flex items-center gap-2 px-4 py-2 bg-rose-500/10 hover:bg-rose-500 text-rose-500 hover:text-white border border-rose-500/20 rounded-xl transition-all duration-300 font-bold text-xs group active:scale-95"
            >
              <LogOut size={16} className="group-hover:-translate-x-0.5 transition-transform" />
              <span className="hidden sm:inline">Sign Out</span>
            </button>
          </div>
        </header>

        <main className="flex-1 p-4 md:p-8 overflow-y-auto max-h-screen custom-scrollbar">
          <div className="max-w-5xl mx-auto pb-20 md:pb-0">
            {/* Page Transition Wrapper */}
            <div key={activeTab} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              {activeEmployee ? (
                <>
                  {activeTab === 'dashboard' && stats && (
                    <Dashboard 
                      stats={stats} 
                      employee={activeEmployee} 
                      records={records} 
                      onAddRecord={(r) => {
                        const filtered = records.filter(rec => !(rec.date === r.date && rec.employeeId === r.employeeId));
                        setRecords([...filtered, r]);
                      }} 
                    />
                  )}
                  {activeTab === 'calendar' && (
                    <Calendar 
                      employee={activeEmployee} 
                      records={records.filter(r => r.employeeId === activeEmployee.id)}
                      onAddRecord={(r) => {
                        const filtered = records.filter(rec => !(rec.date === r.date && rec.employeeId === r.employeeId));
                        setRecords([...filtered, r]);
                      }}
                      onDeleteRecord={(date) => {
                        setRecords(records.filter(r => !(r.date === date && r.employeeId === activeEmployee.id)));
                      }}
                    />
                  )}
                  {activeTab === 'leaves' && (
                    <LeaveManager 
                      employee={activeEmployee}
                      records={records.filter(r => r.employeeId === activeEmployee.id)}
                      leaveRequests={leaveRequests.filter(l => l.employeeId === activeEmployee.id)}
                      onAddRequest={(r) => setLeaveRequests([...leaveRequests, r])}
                    />
                  )}
                  {activeTab === 'reports' && (
                    <Reports 
                      employee={activeEmployee} 
                      records={records.filter(r => r.employeeId === activeEmployee.id)} 
                    />
                  )}
                </>
              ) : (
                <div className="glass p-12 text-center rounded-[3rem] border border-sky-500/20">
                  <Users size={48} className="mx-auto text-sky-400 mb-4 opacity-50" />
                  <h2 className="text-2xl font-bold mb-2">No Active Profile</h2>
                  <p className="text-slate-500 mb-6">You need to register yourself as an employee to see the dashboard.</p>
                  <button 
                    onClick={() => setActiveTab('staff')}
                    className="bg-sky-500 px-8 py-3 rounded-2xl font-bold shadow-xl shadow-sky-500/20"
                  >
                    Go to Staff Manager
                  </button>
                </div>
              )}

              {activeTab === 'staff' && (
                <StaffManager 
                  employees={employees}
                  onAdd={(e) => setEmployees([...employees, e])}
                  onUpdate={(e) => setEmployees(employees.map(emp => emp.id === e.id ? e : emp))}
                  onDelete={(id) => setEmployees(employees.filter(e => e.id !== id))}
                />
              )}

              {activeTab === 'approvals' && (
                <LeaveApproval 
                  requests={leaveRequests}
                  employees={employees}
                  onApprove={(req) => {
                    setLeaveRequests(leaveRequests.map(l => l.id === req.id ? { ...l, status: 'Approved' } : l));
                    const start = new Date(req.startDate);
                    const end = new Date(req.endDate);
                    const newRecords: AttendanceRecord[] = [];
                    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
                      const dateStr = d.toISOString().split('T')[0];
                      newRecords.push({
                        employeeId: req.employeeId,
                        date: dateStr,
                        status: req.type,
                        notes: `Approved Leave: ${req.reason}`
                      });
                    }
                    const filteredRecords = records.filter(r => 
                      !(r.employeeId === req.employeeId && newRecords.some(nr => nr.date === r.date))
                    );
                    setRecords([...filteredRecords, ...newRecords]);
                  }}
                  onReject={(id) => setLeaveRequests(leaveRequests.map(l => l.id === id ? { ...l, status: 'Rejected' } : l))}
                />
              )}

              {activeTab === 'settings' && (
                <SettingsView 
                  settings={settings}
                  onSave={setSettings}
                />
              )}
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

