import React, { useState, useRef } from 'react';
import { UserSettings, Holiday } from '../types';
import { Save, Wallet, Watch, ShieldAlert, Calendar as CalendarIcon, Trash2, Plus, X, Download, Upload, FileSpreadsheet } from 'lucide-react';
import { downloadCSV } from '../utils';

interface Props {
  settings: UserSettings;
  onSave: (s: UserSettings) => void;
}

const DAYS = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];

const SettingsView: React.FC<Props> = ({ settings, onSave }) => {
  const [localSettings, setLocalSettings] = useState<UserSettings>(settings);
  const [showSuccess, setShowSuccess] = useState(false);
  const [newHoliday, setNewHoliday] = useState<Holiday>({ date: '', name: '' });
  const holidayFileInputRef = useRef<HTMLInputElement>(null);

  const handleSave = () => {
    onSave(localSettings);
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 3000);
  };

  const toggleWeeklyOff = (day: number) => {
    const current = localSettings.weeklyOffs || [];
    const updated = current.includes(day) 
      ? current.filter(d => d !== day) 
      : [...current, day];
    setLocalSettings({ ...localSettings, weeklyOffs: updated });
  };

  const addHoliday = () => {
    if (!newHoliday.date || !newHoliday.name) return;
    // Avoid exact date duplicates
    if (localSettings.holidays.some(h => h.date === newHoliday.date)) {
      alert("A holiday already exists for this date.");
      return;
    }
    setLocalSettings({
      ...localSettings,
      holidays: [...(localSettings.holidays || []), newHoliday]
    });
    setNewHoliday({ date: '', name: '' });
  };

  const removeHoliday = (date: string) => {
    setLocalSettings({
      ...localSettings,
      holidays: (localSettings.holidays || []).filter(h => h.date !== date)
    });
  };

  const handleExportHolidays = () => {
    if (localSettings.holidays.length === 0) {
      alert("No holidays to export.");
      return;
    }
    let csv = "Date,Holiday Name\n";
    localSettings.holidays.forEach(h => {
      csv += `${h.date},"${h.name.replace(/"/g, '""')}"\n`;
    });
    downloadCSV(csv, `attendify_holidays_${new Date().getFullYear()}.csv`);
  };

  const handleImportHolidays = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
      if (lines.length < 2) {
        alert("Invalid CSV file.");
        return;
      }

      const importedHolidays: Holiday[] = [];
      const existingDates = new Set(localSettings.holidays.map(h => h.date));

      // Simple CSV parsing assuming first col is date, second is name
      for (let i = 1; i < lines.length; i++) {
        const line = lines[i];
        const parts = line.split(/,(.+)/); // Split at first comma
        if (parts.length >= 2) {
          const date = parts[0].trim();
          let name = parts[1].trim();

          // Basic date format validation (YYYY-MM-DD)
          if (/^\d{4}-\d{2}-\d{2}$/.test(date)) {
            // Unquote name if quoted
            if (name.startsWith('"') && name.endsWith('"')) {
              name = name.substring(1, name.length - 1).replace(/""/g, '"');
            }
            if (!existingDates.has(date)) {
              importedHolidays.push({ date, name });
            }
          }
        }
      }

      if (importedHolidays.length > 0) {
        setLocalSettings({
          ...localSettings,
          holidays: [...localSettings.holidays, ...importedHolidays]
        });
        alert(`Successfully imported ${importedHolidays.length} new holidays.`);
      } else {
        alert("No new or valid holidays found in the CSV.");
      }
      // Reset file input
      if (holidayFileInputRef.current) holidayFileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      <div className="glass p-6 rounded-3xl border border-white/5">
        <h2 className="text-2xl font-bold mb-1">Configuration</h2>
        <p className="text-slate-500 text-sm">Personalize your salary logic & leave policies</p>
      </div>

      {/* Salary Settings */}
      <div className="glass p-6 rounded-3xl border border-white/5 space-y-6">
        <div className="flex items-center gap-2 mb-2">
          <Wallet className="text-sky-400" size={20} />
          <h3 className="font-bold text-lg">Financials</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase">Monthly Base Salary (INR)</label>
            <input
              type="number"
              value={localSettings.monthlySalary}
              onChange={e => setLocalSettings({ ...localSettings, monthlySalary: Number(e.target.value) })}
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-sky-500"
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase">OT Hourly Rate (INR)</label>
            <input
              type="number"
              value={localSettings.otRate}
              onChange={e => setLocalSettings({ ...localSettings, otRate: Number(e.target.value) })}
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-sky-500"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-xs font-bold text-slate-500 uppercase">Standard Daily Hours</label>
          <input
            type="number"
            step="0.5"
            value={localSettings.dailyWorkHours}
            onChange={e => setLocalSettings({ ...localSettings, dailyWorkHours: Number(e.target.value) })}
            className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-sky-500"
          />
          <p className="text-[10px] text-slate-500 italic">OT will be calculated after these hours.</p>
        </div>
      </div>

      {/* Schedule Settings */}
      <div className="glass p-6 rounded-3xl border border-white/5 space-y-6">
        <div className="flex items-center gap-2 mb-2">
          <Watch className="text-purple-400" size={20} />
          <h3 className="font-bold text-lg">Work Schedule</h3>
        </div>

        <div className="space-y-3">
          <label className="text-xs font-bold text-slate-500 uppercase">Weekly Off Days</label>
          <div className="flex flex-wrap gap-2">
            {DAYS.map((day, idx) => (
              <button
                key={day}
                onClick={() => toggleWeeklyOff(idx)}
                className={`px-4 py-2 rounded-xl border text-xs font-bold transition-all ${
                  localSettings.weeklyOffs?.includes(idx)
                    ? 'bg-sky-500 border-sky-500 text-white shadow-lg shadow-sky-500/20'
                    : 'bg-slate-900 border-white/10 text-slate-500'
                }`}
              >
                {day}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Holiday Management */}
      <div className="glass p-6 rounded-3xl border border-white/5 space-y-6">
        <div className="flex items-center justify-between mb-2">
          <div className="flex items-center gap-2">
            <CalendarIcon className="text-pink-400" size={20} />
            <h3 className="font-bold text-lg">Public Holidays</h3>
          </div>
          <div className="flex items-center gap-2">
            <button 
              onClick={handleExportHolidays}
              title="Export to CSV"
              className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl transition-colors border border-white/10"
            >
              <Download size={16} />
            </button>
            <button 
              onClick={() => holidayFileInputRef.current?.click()}
              title="Import from CSV"
              className="p-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl transition-colors border border-white/10"
            >
              <Upload size={16} />
            </button>
            <input 
              type="file" 
              accept=".csv" 
              ref={holidayFileInputRef} 
              onChange={handleImportHolidays} 
              className="hidden" 
            />
          </div>
        </div>

        <div className="flex gap-2">
          <input 
            type="date"
            value={newHoliday.date}
            onChange={e => setNewHoliday({...newHoliday, date: e.target.value})}
            className="flex-1 bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs"
          />
          <input 
            type="text"
            placeholder="Holiday Name"
            value={newHoliday.name}
            onChange={e => setNewHoliday({...newHoliday, name: e.target.value})}
            className="flex-[2] bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs"
          />
          <button 
            onClick={addHoliday}
            className="p-2 bg-sky-500 rounded-xl text-white hover:bg-sky-600 transition-colors"
          >
            <Plus size={18} />
          </button>
        </div>

        <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar">
          {(localSettings.holidays || []).length > 0 ? (
            [...localSettings.holidays].sort((a, b) => a.date.localeCompare(b.date)).map(holiday => (
              <div key={holiday.date} className="flex items-center justify-between p-3 bg-white/5 rounded-xl border border-white/5">
                <div className="flex flex-col">
                  <span className="text-xs font-bold">{holiday.name}</span>
                  <span className="text-[10px] text-slate-500">{holiday.date}</span>
                </div>
                <button onClick={() => removeHoliday(holiday.date)} className="text-rose-500 hover:bg-rose-500/10 p-1.5 rounded-lg transition-colors">
                  <Trash2 size={14} />
                </button>
              </div>
            ))
          ) : (
            <p className="text-center text-slate-600 text-xs py-4 italic">No holidays added yet</p>
          )}
        </div>
      </div>

      {/* Quota Settings */}
      <div className="glass p-6 rounded-3xl border border-white/5 space-y-6">
        <div className="flex items-center gap-2 mb-2">
          <ShieldAlert className="text-amber-400" size={20} />
          <h3 className="font-bold text-lg">Yearly Leave Quotas</h3>
        </div>

        <div className="grid grid-cols-3 gap-4">
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-500 uppercase">Sick Leave (SL)</label>
            <input
              type="number"
              value={localSettings.quotas.SL}
              onChange={e => setLocalSettings({ 
                ...localSettings, 
                quotas: { ...localSettings.quotas, SL: Number(e.target.value) } 
              })}
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-white focus:outline-none focus:border-rose-500"
            />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-500 uppercase">Privilege Leave (PL)</label>
            <input
              type="number"
              value={localSettings.quotas.PL}
              onChange={e => setLocalSettings({ 
                ...localSettings, 
                quotas: { ...localSettings.quotas, PL: Number(e.target.value) } 
              })}
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-white focus:outline-none focus:border-emerald-500"
            />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-bold text-slate-500 uppercase">Casual Leave (CL)</label>
            <input
              type="number"
              value={localSettings.quotas.CL}
              onChange={e => setLocalSettings({ 
                ...localSettings, 
                quotas: { ...localSettings.quotas, CL: Number(e.target.value) } 
              })}
              className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-white focus:outline-none focus:border-purple-500"
            />
          </div>
        </div>
      </div>

      <button
        onClick={handleSave}
        className="w-full py-4 bg-sky-500 text-white font-bold rounded-2xl shadow-xl shadow-sky-500/20 hover:bg-sky-600 transition-all flex items-center justify-center gap-2 active:scale-[0.98]"
      >
        <Save size={20} /> {showSuccess ? 'Settings Saved Successfully!' : 'Save All Preferences'}
      </button>

      <div className="text-center p-4">
        <p className="text-[10px] text-slate-600 uppercase font-bold tracking-widest">Calculated on 26 working days cycle</p>
      </div>
    </div>
  );
};

