}

import React, { useState, useMemo } from 'react';
import { AttendanceRecord, Employee, LeaveRequest } from '../types';
import { ClipboardList, PieChart, Plus, X, Info } from 'lucide-react';

interface Props {
  employee: Employee;
  records: AttendanceRecord[];
  leaveRequests: LeaveRequest[];
  onAddRequest: (r: LeaveRequest) => void;
}

const LeaveManager: React.FC<Props> = ({ employee, records, leaveRequests, onAddRequest }) => {
  const [showForm, setShowForm] = useState(false);

  // Calculate available leave types based on quotas
  const availableTypes = useMemo(() => {
    const types: { value: 'SL' | 'PL' | 'CL' | 'Unpaid'; label: string }[] = [];
    if (employee.quotas.PL > 0) types.push({ value: 'PL', label: 'Paid Leave (PL)' });
    if (employee.quotas.SL > 0) types.push({ value: 'SL', label: 'Sick Leave (SL)' });
    if (employee.quotas.CL > 0) types.push({ value: 'CL', label: 'Casual Leave (CL)' });
    types.push({ value: 'Unpaid', label: 'Unpaid Leave' });
    return types;
  }, [employee.quotas]);

  const [formData, setFormData] = useState({ 
    type: availableTypes[0]?.value || 'Unpaid', 
    start: '', 
    end: '', 
    reason: '' 
  });

  const currentYear = new Date().getFullYear().toString();
  const yearlyRecords = records.filter(r => r.date.startsWith(currentYear));

  const getUsage = (type: string) => yearlyRecords.filter(r => r.status === type).length;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddRequest({
      id: Date.now().toString(),
      employeeId: employee.id,
      type: formData.type as any,
      startDate: formData.start,
      endDate: formData.end,
      reason: formData.reason,
      status: 'Pending',
      createdAt: new Date().toISOString()
    });
    setShowForm(false);
  };

  const LeaveCard = ({ label, used, total, color }: any) => {
    const remaining = Math.max(0, total - used);
    const progress = (used / total) * 100;
    return (
      <div className="glass p-5 rounded-2xl border border-white/5 space-y-4">
        <div className="flex justify-between items-center">
          <h4 className="font-bold text-lg">{label}</h4>
          <span className={`text-[10px] px-2 py-1 rounded-md bg-${color}-500/10 text-${color}-400 font-bold uppercase`}>Yearly</span>
        </div>
        <div className="flex items-baseline space-x-2">
          <span className="text-3xl font-bold font-heading">{remaining}</span>
          <span className="text-slate-500 text-xs">days left</span>
        </div>
        <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
          <div className={`h-full bg-${color}-500 transition-all duration-1000`} style={{ width: `${Math.min(100, progress)}%` }} />
        </div>
        <p className="text-[10px] text-slate-500 font-medium">Used: {used} / {total} days</p>
      </div>
    );
  };

  const hasPaidQuotas = employee.quotas.SL > 0 || employee.quotas.PL > 0 || employee.quotas.CL > 0;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">Leave Center</h2>
          <p className="text-slate-500 text-sm">Apply and track leave history</p>
        </div>
        <button 
          onClick={() => {
            setFormData({ ...formData, type: availableTypes[0]?.value || 'Unpaid' });
            setShowForm(true);
          }} 
          className="bg-sky-500 hover:bg-sky-600 px-4 py-2.5 rounded-xl font-bold text-sm flex items-center gap-2 transition-all active:scale-95 shadow-lg shadow-sky-500/20"
        >
          <Plus size={18} /> Apply Leave
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {employee.quotas.SL > 0 && <LeaveCard label="Sick (SL)" used={getUsage('SL')} total={employee.quotas.SL} color="rose" />}
        {employee.quotas.PL > 0 && <LeaveCard label="Paid (PL)" used={getUsage('PL')} total={employee.quotas.PL} color="emerald" />}
        {employee.quotas.CL > 0 && <LeaveCard label="Casual (CL)" used={getUsage('CL')} total={employee.quotas.CL} color="purple" />}

        {!hasPaidQuotas && (
          <div className="md:col-span-3 glass p-6 rounded-2xl border border-sky-500/10 bg-sky-500/5 flex items-center gap-4">
            <div className="p-3 bg-sky-500/20 rounded-xl text-sky-400">
              <Info size={24} />
            </div>
            <div>
              <h4 className="font-bold">No Paid Leave Quotas</h4>
              <p className="text-sm text-slate-400">All leave requests for this profile will be processed as Unpaid Leave.</p>
            </div>
          </div>
        )}
      </div>

      <div className="glass rounded-3xl overflow-hidden border border-white/5 shadow-xl">
        <div className="p-4 border-b border-white/5 bg-white/5 font-bold flex items-center gap-2">
          <PieChart size={18} className="text-sky-400"/> Request Status
        </div>
        <div className="divide-y divide-white/5">
          {leaveRequests.length > 0 ? leaveRequests.sort((a,b) => b.createdAt.localeCompare(a.createdAt)).map(r => (
            <div key={r.id} className="p-4 flex justify-between items-center hover:bg-white/5 transition-colors">
              <div>
                <div className="flex items-center gap-2">
                  <p className="font-bold text-sm">{r.type === 'Unpaid' ? 'Unpaid' : r.type} Request</p>
                  {r.type === 'Unpaid' && <span className="text-[8px] bg-slate-500/20 text-slate-400 px-1.5 py-0.5 rounded font-bold uppercase">Salary Deducted</span>}
                </div>
                <p className="text-xs text-slate-500">{r.startDate} to {r.endDate}</p>
              </div>
              <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border ${
                r.status === 'Pending' ? 'bg-amber-500/10 text-amber-500 border-amber-500/20' : 
                r.status === 'Approved' ? 'bg-emerald-500/10 text-emerald-500 border-emerald-500/20' : 'bg-rose-500/10 text-rose-500 border-rose-500/20'
              }`}>
                {r.status}
              </span>
            </div>
          )) : <p className="p-8 text-center text-slate-500 text-sm italic">No recent requests</p>}
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-950/90 backdrop-blur-md" onClick={() => setShowForm(false)} />
          <form onSubmit={handleSubmit} className="relative glass w-full max-w-md p-8 rounded-[2.5rem] border border-sky-500/30 shadow-2xl space-y-4 animate-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-2">
              <h3 className="text-2xl font-bold font-heading">Application</h3>
              <button type="button" onClick={() => setShowForm(false)} className="text-slate-400 hover:text-white p-1">
                <X size={24} />
              </button>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Leave Type</label>
              <select 
                value={formData.type} 
                onChange={e => setFormData({...formData, type: e.target.value as any})} 
                className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-sky-500 appearance-none transition-all"
              >
                {availableTypes.map(t => (
                  <option key={t.value} value={t.value}>{t.label}</option>
                ))}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Start Date</label>
                <input type="date" required value={formData.start} onChange={e => setFormData({...formData, start: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-sky-500" />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">End Date</label>
                <input type="date" required value={formData.end} onChange={e => setFormData({...formData, end: e.target.value})} className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 text-white focus:outline-none focus:border-sky-500" />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-bold text-slate-500 uppercase ml-1">Reason for Leave</label>
              <textarea 
                required 
                value={formData.reason} 
                onChange={e => setFormData({...formData, reason: e.target.value})} 
                className="w-full bg-slate-900 border border-white/10 rounded-xl px-4 py-3 h-24 text-white focus:outline-none focus:border-sky-500 resize-none"
                placeholder="Brief description..."
              />
            </div>

            <div className="pt-2">
              <button 
                type="submit" 
                className="w-full py-4 bg-sky-500 hover:bg-sky-600 text-white font-bold rounded-2xl shadow-xl shadow-sky-500/30 transition-all active:scale-95"
              >
                Submit Leave Request
              </button>
              <p className="text-[10px] text-center text-slate-500 mt-4 font-medium uppercase tracking-widest">Calculated on 26-day working cycle</p>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default LeaveManager;

import React from 'react';
import { LeaveRequest, Employee } from '../types';
import { Check, X, Clock, Calendar } from 'lucide-react';

interface Props {
  requests: LeaveRequest[];
  employees: Employee[];
  onApprove: (req: LeaveRequest) => void;
  onReject: (id: string) => void;
}

const LeaveApproval: React.FC<Props> = ({ requests, employees, onApprove, onReject }) => {
  const pending = requests.filter(r => r.status === 'Pending').sort((a,b) => b.createdAt.localeCompare(a.createdAt));

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold font-heading">Leave Requests</h2>
        <span className="bg-amber-500/10 text-amber-500 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest border border-amber-500/20">
          {pending.length} Pending
        </span>
      </div>

      <div className="space-y-4">
        {pending.length === 0 ? (
          <div className="glass p-12 text-center rounded-3xl border border-white/5 italic text-slate-500">
            No pending leave requests at the moment.
          </div>
        ) : (
          pending.map(req => {
            const emp = employees.find(e => e.id === req.employeeId);
            return (
              <div key={req.id} className="glass p-6 rounded-3xl border border-white/5 flex flex-col md:flex-row md:items-center justify-between gap-4 animate-in slide-in-from-right duration-300">
                <div className="flex gap-4">
                  <div className="w-12 h-12 bg-sky-500/10 rounded-2xl flex items-center justify-center text-sky-400 shrink-0">
                    <Calendar size={24} />
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                      <h4 className="font-bold text-lg">{emp?.name || 'Unknown Staff'}</h4>
                      <span className={`px-2 py-0.5 rounded text-[8px] font-bold uppercase border ${
                        req.type === 'Unpaid' ? 'bg-slate-500/10 text-slate-400 border-white/10' : 'bg-sky-500/10 text-sky-400 border-sky-500/20'
                      }`}>
                        {req.type}
                      </span>
                    </div>
                    <p className="text-xs text-slate-400 mb-2">Requested from {req.startDate} to {req.endDate}</p>
                    <p className="text-sm bg-white/5 p-3 rounded-xl italic border border-white/5">"{req.reason}"</p>
                  </div>
                </div>
                <div className="flex gap-3">
                  <button 
                    onClick={() => onApprove(req)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-500 hover:bg-emerald-600 px-6 py-2.5 rounded-xl font-bold text-sm shadow-lg shadow-emerald-500/20 transition-all active:scale-95 text-white"
                  >
                    <Check size={18} /> Approve
                  </button>
                  <button 
                    onClick={() => onReject(req.id)}
                    className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-rose-500/10 text-rose-500 hover:bg-rose-500 hover:text-white border border-rose-500/20 px-6 py-2.5 rounded-xl font-bold text-sm transition-all active:scale-95"
                  >
                    <X size={18} /> Reject
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* History section */}
      <div className="mt-12">
        <h3 className="text-lg font-bold font-heading mb-4 text-slate-400">Request History</h3>
        <div className="glass rounded-2xl overflow-hidden divide-y divide-white/5 shadow-xl">
          {requests.filter(r => r.status !== 'Pending').slice(0, 10).map(req => {
            const emp = employees.find(e => e.id === req.employeeId);
            return (
              <div key={req.id} className="p-4 flex items-center justify-between text-sm hover:bg-white/5 transition-colors">
                <div className="flex items-center gap-2">
                  <span className="font-bold text-white">{emp?.name}</span>
                  <span className={`px-1.5 py-0.5 rounded text-[8px] font-bold uppercase ${
                    req.type === 'Unpaid' ? 'bg-slate-800 text-slate-500' : 'bg-sky-500/10 text-sky-500'
                  }`}>
                    {req.type}
                  </span>
                  <span className="text-slate-500 mx-1">•</span>
                  <span className="text-slate-400 text-xs">{req.startDate}</span>
                </div>
                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-widest ${
                  req.status === 'Approved' ? 'text-emerald-400 bg-emerald-500/10' : 'text-rose-400 bg-rose-500/10'
                }`}>
                  {req.status}
                </span>
              </div>
            );
          })}
          {requests.filter(r => r.status !== 'Pending').length === 0 && (
             <p className="p-8 text-center text-slate-500 text-sm italic">No history records found.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default LeaveApproval;

export type AttendanceStatus = 'Duty' | 'SL' | 'PL' | 'CL' | 'Unpaid' | 'Half-Day' | 'Weekly Off' | 'Holiday' | 'Absent';
export type LeaveRequestStatus = 'Pending' | 'Approved' | 'Rejected';
export type UserRole = 'admin' | 'employee';

export interface User {
  id: string;
  username: string;
  password?: string;
  fullName: string;
  role: UserRole;
  accessibleTabs: string[];
  linkedEmployeeId?: string;
  provider: 'google' | 'facebook' | 'apple' | 'email' | 'phone' | 'credentials';
}

export interface LeaveQuotas {
  SL: number;
  PL: number;
  CL: number;
}

export interface Holiday {
  date: string;
  name: string;
}

export interface Employee {
  id: string;
  employeeId: string; // Auto-generated unique ID (e.g. EMP-001)
  name: string;
  monthlySalary: number;
  otRate: number;
  dailyWorkHours: number;
  quotas: LeaveQuotas;
  role: string;
  joinedDate: string;
  weeklyOffs: number[];
  notes?: string;
}

export interface AttendanceRecord {
  employeeId: string;
  date: string;
  checkIn?: string;
  checkOut?: string;
  status: AttendanceStatus;
  notes: string;
  totalHours?: number;
  otHours?: number;
}

export interface LeaveRequest {
  id: string;
  employeeId: string;
  type: 'SL' | 'PL' | 'CL' | 'Unpaid';
  startDate: string;
  endDate: string;
  reason: string;
  status: LeaveRequestStatus;
  createdAt: string;
}

export interface UserSettings {
  monthlySalary: number;
  otRate: number;
  dailyWorkHours: number;
  quotas: LeaveQuotas;
  weeklyOffs: number[];
  holidays: Holiday[];
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Calendar as CalendarIcon, 
  ClipboardList, 
  Settings as SettingsIcon,
  Download,
  Users,
  MessageSquare,
  LogOut,
  ShieldCheck
} from 'lucide-react';
import { AttendanceRecord, Employee, LeaveRequest, UserSettings, User } from './types';
import Dashboard from './components/Dashboard';
import Calendar from './components/Calendar';
import LeaveManager from './components/LeaveManager';
import SettingsView from './components/SettingsView';
import Reports from './components/Reports';
import StaffManager from './components/StaffManager';
import LeaveApproval from './components/LeaveApproval';
import AuthView from './components/AuthView';
import { calculateSalary } from './utils';

const EMPLOYEES_KEY = 'neon_employees_v2';
const RECORDS_KEY = 'neon_records_v2';
const LEAVES_KEY = 'neon_leaves_v2';
const SETTINGS_KEY = 'neon_settings_v2';
const AUTH_SESSION_KEY = 'neon_user_session';
const USERS_LIST_KEY = 'attendify_auth_users';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');

  // App Data State
  const [users, setUsers] = useState<User[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [records, setRecords] = useState<AttendanceRecord[]>([]);
  const [leaveRequests, setLeaveRequests] = useState<LeaveRequest[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    monthlySalary: 30000,
    otRate: 200,
    dailyWorkHours: 8.5,
    quotas: { SL: 12, PL: 15, CL: 10 },
    weeklyOffs: [0],
    holidays: []
  });

  // Load state from local storage
  useEffect(() => {
    const savedSession = localStorage.getItem(AUTH_SESSION_KEY);
    if (savedSession) setCurrentUser(JSON.parse(savedSession));

    const savedUsers = localStorage.getItem(USERS_LIST_KEY);
    if (savedUsers) setUsers(JSON.parse(savedUsers));

    const savedEmps = localStorage.getItem(EMPLOYEES_KEY);
    if (savedEmps) setEmployees(JSON.parse(savedEmps));

    const savedRecords = localStorage.getItem(RECORDS_KEY);
    if (savedRecords) setRecords(JSON.parse(savedRecords));

    const savedLeaves = localStorage.getItem(LEAVES_KEY);
    if (savedLeaves) setLeaveRequests(JSON.parse(savedLeaves));

    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) setSettings(JSON.parse(savedSettings));
  }, []);

  // Persist state
  useEffect(() => {
    localStorage.setItem(USERS_LIST_KEY, JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem(EMPLOYEES_KEY, JSON.stringify(employees));
  }, [employees]);

  useEffect(() => {
    localStorage.setItem(RECORDS_KEY, JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem(LEAVES_KEY, JSON.stringify(leaveRequests));
  }, [leaveRequests]);

  useEffect(() => {
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [settings]);

  // Sync session if currentUser data changes in users list
  useEffect(() => {
    if (currentUser) {
      const updated = users.find(u => u.id === currentUser.id);
      if (updated && JSON.stringify(updated) !== JSON.stringify(currentUser)) {
        setCurrentUser(updated);
        localStorage.setItem(AUTH_SESSION_KEY, JSON.stringify(updated));
      }
    }
  }, [users, currentUser]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem(AUTH_SESSION_KEY, JSON.stringify(user));
    // Set first available tab as active
    if (user.accessibleTabs.length > 0) {
      setActiveTab(user.accessibleTabs[0]);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem(AUTH_SESSION_KEY);
  };

  const activeEmployee = useMemo(() => {
    if (!currentUser || employees.length === 0) return null;
    if (currentUser.role === 'admin') return employees[0]; // Admin sees first as default or none
    return employees.find(e => e.id === currentUser.linkedEmployeeId) || null;
  }, [employees, currentUser]);

  const stats = useMemo(() => {
    if (!activeEmployee) return null;
    const monthlyRecords = records.filter(r => 
      r.employeeId === activeEmployee.id && 
      r.date.startsWith(new Date().toISOString().slice(0, 7))
    );
    return calculateSalary(monthlyRecords, activeEmployee);
  }, [records, activeEmployee]);

  if (!currentUser) {
    return <AuthView onLogin={handleLogin} />;
  }

  const navConfigs = [
    { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
    { id: 'calendar', icon: CalendarIcon, label: 'Attendance' },
    { id: 'leaves', icon: ClipboardList, label: 'Leaves' },
    { id: 'reports', icon: Download, label: 'Reports' },
    { id: 'staff', icon: Users, label: 'Staff Manager' },
    { id: 'approvals', icon: MessageSquare, label: 'Approvals' },
    { id: 'settings', icon: SettingsIcon, label: 'Settings' },
  ];

  const visibleNavItems = navConfigs.filter(item => 
    currentUser.accessibleTabs.includes(item.id)
  );

  const NavItem = ({ id, icon: Icon, label }: any) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex items-center gap-3 px-4 py-3 rounded-2xl transition-all duration-300 w-full group ${
        activeTab === id 
          ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/30 font-bold' 
          : 'text-slate-400 hover:text-white hover:bg-white/5'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : 'group-hover:scale-110 transition-transform'} />
      <span className="hidden lg:block text-sm">{label}</span>
    </button>
  );

  const MobileNavItem = ({ id, icon: Icon, label }: any) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all duration-300 ${
        activeTab === id 
          ? 'text-sky-400' 
          : 'text-slate-500'
      }`}
    >
      <div className={`p-2 rounded-xl transition-all ${activeTab === id ? 'bg-sky-500/10' : ''}`}>
        <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      </div>
      <span className="text-[9px] font-bold uppercase tracking-tight">{label}</span>
    </button>
  );

  const tabLabels: Record<string, string> = {
    dashboard: 'Dashboard',
    calendar: 'Attendance Log',
    leaves: 'Leave Center',
    reports: 'Monthly Reports',
    staff: 'Staff Directory',
    approvals: 'Admin Approvals',
    settings: 'App Settings'
  };

  return (
    <div className="flex flex-col h-full bg-[#0f172a] text-slate-100 overflow-hidden">
      <header className="flex-shrink-0 z-50 glass border-b border-white/5 px-4 md:px-6 py-3 md:py-4 flex items-center justify-between">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="p-1.5 md:p-2 bg-sky-500 rounded-lg md:rounded-xl shadow-lg shadow-sky-500/30 flex items-center justify-center">
            <ShieldCheck className="text-white" size={20} />
          </div>
          <h1 className="text-lg md:text-2xl font-black font-heading tracking-tight neon-text">Attendify</h1>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <div className="hidden sm:flex items-center gap-2 md:gap-3 glass-dark border border-white/10 px-3 py-1.5 rounded-xl shadow-inner">
            <div className="w-6 h-6 md:w-8 md:h-8 rounded-full bg-gradient-to-br from-sky-400 to-blue-600 flex items-center justify-center font-bold text-[10px] md:text-xs shadow-lg">
              {currentUser.fullName.charAt(0)}
            </div>
            <div className="flex flex-col text-left">
              <span className="text-[10px] md:text-xs font-bold leading-tight">{currentUser.fullName}</span>
              <span className="text-[8px] md:text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                {currentUser.role} @{currentUser.username}
              </span>
            </div>
          </div>

          <button 
            onClick={handleLogout}
            className="flex items-center gap-1.5 md:gap-2 px-3 md:px-4 py-1.5 md:py-2 bg-rose-500/10 hover:bg-rose-500 text-rose-500 hover:text-white border border-rose-500/20 rounded-lg md:rounded-xl transition-all duration-300 font-bold text-[10px] md:text-xs group active:scale-95 shadow-lg shadow-rose-500/5"
          >
            <LogOut size={14} className="group-hover:-translate-x-0.5 transition-transform" />
            <span className="hidden xs:inline">Sign Out</span>
          </button>
        </div>
      </header>

      <div className="flex flex-1 relative overflow-hidden">
        <aside className="hidden md:flex w-20 lg:w-64 glass-dark border-r border-white/5 p-4 flex-col gap-2 z-40 overflow-y-auto scrollbar-hide">
          <nav className="flex flex-col gap-2">
            {visibleNavItems.map(item => (
              <NavItem key={item.id} id={item.id} icon={item.icon} label={item.label} />
            ))}
          </nav>
        </aside>

        <main className="flex-1 overflow-y-auto custom-scrollbar bg-slate-950/20 p-4 md:p-8 pb-24 md:pb-8">
          <div className="max-w-5xl mx-auto h-full">
            <div key={`title-${activeTab}`} className="mb-6 md:mb-8 animate-in slide-in-from-left-4 fade-in duration-500">
              <h2 className="text-2xl md:text-3xl font-bold font-heading text-white">
                {tabLabels[activeTab]}
              </h2>
              <div className="h-1 w-10 md:w-12 bg-sky-500 rounded-full mt-2 shadow-[0_0_8px_rgba(14,165,233,0.5)]" />
            </div>

            <div key={activeTab} className="animate-in fade-in slide-in-from-bottom-6 duration-500">
              {activeTab === 'dashboard' && stats && activeEmployee && (
                <Dashboard 
                  stats={stats} 
                  employee={activeEmployee} 
                  records={records} 
                  holidays={settings.holidays}
                  onAddRecord={(r) => {
                    const filtered = records.filter(rec => !(rec.date === r.date && rec.employeeId === r.employeeId));
                    setRecords([...filtered, r]);
                  }} 
                />
              )}
              {activeTab === 'calendar' && activeEmployee && (
                <Calendar 
                  employee={activeEmployee} 
                  records={records.filter(r => r.employeeId === activeEmployee.id)}
                  holidays={settings.holidays}
                  onAddRecord={(r) => {
                    const filtered = records.filter(rec => !(rec.date === r.date && rec.employeeId === r.employeeId));
                    setRecords([...filtered, r]);
                  }}
                  onDeleteRecord={(date) => {
                    setRecords(records.filter(r => !(r.date === date && r.employeeId === activeEmployee.id)));
                  }}
                />
              )}
              {activeTab === 'leaves' && activeEmployee && (
                <LeaveManager 
                  employee={activeEmployee}
                  records={records.filter(r => r.employeeId === activeEmployee.id)}
                  leaveRequests={leaveRequests.filter(l => l.employeeId === activeEmployee.id)}
                  onAddRequest={(r) => setLeaveRequests([...leaveRequests, r])}
                />
              )}
              {activeTab === 'reports' && activeEmployee && (
                <Reports 
                  employee={activeEmployee} 
                  records={records.filter(r => r.employeeId === activeEmployee.id)} 
                />
              )}

              {activeTab === 'staff' && currentUser.role === 'admin' && (
                <StaffManager 
                  employees={employees}
                  users={users}
                  globalWeeklyOffs={settings.weeklyOffs}
                  onAdd={(e, u) => {
                    setEmployees([...employees, e]);
                    setUsers([...users, u]);
                  }}
                  onUpdate={(e, u) => {
                    setEmployees(employees.map(emp => emp.id === e.id ? e : emp));
                    if (u) setUsers(users.map(usr => usr.id === u.id ? u : usr));
                  }}
                  onDelete={(id) => {
                    const emp = employees.find(e => e.id === id);
                    setEmployees(employees.filter(e => e.id !== id));
                    setUsers(users.filter(u => u.linkedEmployeeId !== id));
                  }}
                />
              )}

              {activeTab === 'approvals' && currentUser.role === 'admin' && (
                <LeaveApproval 
                  requests={leaveRequests}
                  employees={employees}
                  onApprove={(req) => {
                    setLeaveRequests(leaveRequests.map(l => l.id === req.id ? { ...l, status: 'Approved' } : l));
                    const start = new Date(req.startDate);
                    const end = new Date(req.endDate);
                    const newRecords: AttendanceRecord[] = [];
                    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
                      const dateStr = d.toISOString().split('T')[0];
                      newRecords.push({
                        employeeId: req.employeeId,
                        date: dateStr,
                        status: req.type,
                        notes: `Approved Leave: ${req.reason}`
                      });
                    }
                    const filteredRecords = records.filter(r => 
                      !(r.employeeId === req.employeeId && newRecords.some(nr => nr.date === r.date))
                    );
                    setRecords([...filteredRecords, ...newRecords]);
                  }}
                  onReject={(id) => setLeaveRequests(leaveRequests.map(l => l.id === id ? { ...l, status: 'Rejected' } : l))}
                />
              )}

              {activeTab === 'settings' && currentUser.role === 'admin' && (
                <SettingsView 
                  settings={settings}
                  onSave={setSettings}
                />
              )}
            </div>
          </div>
        </main>
      </div>

      <nav className="md:hidden flex-shrink-0 glass-dark border-t border-white/10 px-2 py-1 flex items-center justify-around z-50 safe-area-bottom">
        {visibleNavItems.map(item => (
          <MobileNavItem key={item.id} id={item.id} icon={item.icon} label={item.label} />
        ))}
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo } from 'react';
