  const [formData, setFormData] = useState({
    name: '',
    role: 'Staff Member',
    salary: 30000,
    otRate: 200,
    dailyHours: 8.5,
    sl: 12, pl: 15, cl: 10,
    notes: '',
    joinedDate: getTodayStr(),
    weeklyOffs: globalWeeklyOffs,
    username: '',
    password: '',
    accessibleTabs: ['dashboard', 'calendar', 'leaves']
