  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const employeeId = editingEmployee?.id || Date.now().toString();
    const readableId = editingEmployee?.employeeId || nextEmployeeId;

    const newEmp: Employee = {
      id: employeeId,
      employeeId: readableId,
      name: formData.name,
      role: formData.role,
      monthlySalary: formData.salary,
      otRate: formData.otRate,
      dailyWorkHours: formData.dailyHours,
      joinedDate: formData.joinedDate,
      weeklyOffs: formData.weeklyOffs,
      quotas: { SL: formData.sl, PL: formData.pl, CL: formData.cl },
      notes: formData.notes
    };

    const linkedUser = users.find(u => u.linkedEmployeeId === employeeId);
    const newUser: User = {
      id: linkedUser?.id || `user-${Date.now()}`,
      username: formData.username,
      password: formData.password,
      fullName: formData.name,
      role: 'employee',
      accessibleTabs: formData.accessibleTabs,
      linkedEmployeeId: employeeId,
      provider: 'credentials'
