              </div>
            </div>
          ))
        ) : (
          <div className="md:col-span-2 glass p-12 rounded-3xl border border-white/5 text-center italic text-slate-600">No staff found.</div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
